import React, { useState, useEffect, useRef, useCallback } from 'react';
import LoginScreen from './components/LoginScreen';
import PartSearchScreen from './components/PartSearchScreen';
import { db } from './firebase';
import { useAppSecurity } from './hooks/useAppSecurity';
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  writeBatch,
  getDocs,
  where,
  limit,
  setDoc,
  deleteField,
  increment,
  getCountFromServer,
  getDoc,
  arrayUnion,
  arrayRemove
} from 'firebase/firestore';

export interface UserData {
  id?: string;
  username: string;
  password: string;
  role: 'ADMIN' | 'USER' | 'LEADER';
  nickname?: string;
  canExportAnalytics?: boolean;
}

export interface DBItem {
  id: string;
  value: string;
  standardTime?: number;
  description?: string;
  coordX?: number;
  coordY?: number;
  distancePx?: number;
}

export interface MapSector {
  id: string;
  name: string;
  coordX: number;
  coordY: number;
  color?: string;
  order?: number;
}

export type PriorityLevel = 'LOW' | 'NORMAL' | 'URGENT';

export interface InventorySession {
    start: number;
    end?: number;
}

export interface Task {
  id: string; 
  text: string;
  partNumber?: string;
  workplace?: string;
  quantity?: string;
  quantityUnit?: string;
  standardTime?: number;
  isDone: boolean;
  priority?: PriorityLevel; 
  completionTime?: string;
  completedBy?: string | null;
  status?: 'completed' | 'incorrectly_entered';
  isMissing?: boolean;
  missingReportedBy?: string | null;
  missingReason?: string;
  isInProgress?: boolean;
  inProgressBy?: string | null;
  createdAt?: number; 
  createdBy?: string;
  startedAt?: number; 
  completedAt?: number; 
  note?: string;
  isBlocked?: boolean; 
  blockedBy?: string | null; 
  isManualBlocked?: boolean; 
  inventoryHistory?: InventorySession[];
  isLogistics?: boolean; 
  isProduction?: boolean;
  isAuditInProgress?: boolean;
  auditBy?: string | null;
  auditFinalBadge?: string | null;
  auditedBy?: string | null;
  auditedAt?: number | null;
  auditResult?: 'OK' | 'NOK' | null;
  auditNote?: string | null;
  expireAt?: number;
  searchExhausted?: boolean;
  searchedBy?: string | null;
  pickedFromSectorId?: string;
}

export interface Notification {
    id: string;
    partNumber: string;
    reason: string;
    reportedBy: string;
    targetUser: string; 
    timestamp: number;
}

export interface PartRequest {
    id: string;
    partNumber: string;
    requestedBy: string;
    requestedAt: number;
}

export interface BreakSchedule {
    id: string;
    name: string;
    startTime: string;
    endTime: string;
}

export interface SystemBreak {
    id: string;
    start: number;
    end?: number;
    isActive: boolean;
}

export interface BOMComponent {
    child: string;
    consumption: number;
}

export interface BOMItem {
    id: string;
    parentPart: string;
    childPart: string;
    quantity: number;
}

export interface BOMRequest {
    id: string;
    parentPart: string;
    requestedBy: string;
    requestedAt: number;
}

export interface Role {
    id: string;
    name: string;
    isSystem?: boolean;
}

export interface Permission {
    id: string;
    roleId: string;
    permissionName: string;
}

export interface SystemConfig {
    maintenanceMode: boolean;
    maintenanceStart?: string;
    maintenanceEnd?: string;
    allowedIPs: string[];
    ipCheckEnabled: boolean;
    adminKey?: string;
    adminLockEnabled?: boolean;
    mapOriginX?: number;
    mapOriginY?: number;
    vzvSpeed?: number;
}

const colorMap: Record<string, string> = {
  blue: 'bg-blue-600 border-blue-500 hover:bg-blue-500',
  green: 'bg-green-600 border-green-500 hover:bg-green-500',
  orange: 'bg-orange-600 border-orange-500 hover:bg-orange-500',
  teal: 'bg-teal-600 border-teal-500 hover:bg-teal-500',
  pink: 'bg-pink-600 border-pink-500 hover:bg-pink-500',
  red: 'bg-red-600 border-red-500 hover:bg-red-500',
  slate: 'bg-slate-900 border-slate-700 hover:bg-slate-800'
};

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');

  // Custom Hook pre bezpečnosť a config
  const { 
    isUnlocked, 
    setIsUnlocked, 
    systemConfig, 
    handleUnlockAttempt, 
    handleUpdateAdminKey,
    handleUpdateSystemConfig
  } = useAppSecurity(currentUserRole, isAuthenticated);

  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]); // ZAISTENÉ: Prázdne pole na začiatku

  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, BOMComponent[]>>({});

  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const [dbLoadWarning, setDbLoadWarning] = useState<boolean>(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  // Stavy pre modálne okno výberu sektora
  const [showSectorModal, setShowSectorModal] = useState(false);
  const [finishingTaskId, setFinishingTaskId] = useState<string | null>(null);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  const checkPermissionRef = (permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  };

  useEffect(() => {
    const storedUser = localStorage.getItem('app_user');
    const storedRole = localStorage.getItem('app_role');
    if (storedUser && storedRole) {
      setCurrentUser(storedUser);
      setCurrentUserRole(storedRole as any);
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallApp = async () => {
    if (!deferredPrompt) return;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
  };

  const handleLogout = () => { 
    setIsAuthenticated(false); 
    setIsUnlocked(false);
    setCurrentUser(''); 
    setCurrentUserRole('USER'); 
    localStorage.removeItem('app_user'); 
    localStorage.removeItem('app_role'); 
    sessionStorage.removeItem('app_unlocked');
  };

  useEffect(() => {
      if (isAuthenticated && currentUserRole !== 'ADMIN') {
          const now = new Date();
          const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
          const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                         currentISO >= systemConfig.maintenanceStart && 
                                         currentISO <= systemConfig.maintenanceEnd;
          if (systemConfig.maintenanceMode || isScheduledMaintenance) {
              handleLogout();
              alert('Systém prešiel do servisného módu. Boli ste odhlásení.');
          }
      }
  }, [systemConfig, isAuthenticated, currentUserRole]);

  useEffect(() => {
    if (!isAuthenticated) return;
    // Optimalizácia: Načítavame len úlohy vytvorené v posledných 3 dňoch.
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const priorityOrder: Record<string, number> = { 'URGENT': 0, 'NORMAL': 1, 'LOW': 2 };
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = priorityOrder[a.priority || 'NORMAL'];
        const pB = priorityOrder[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      return () => { unsubUsers(); unsubRoles(); unsubPerms(); };
  }, []);

  useEffect(() => {
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, string> = {};
          raw.forEach((item: any) => {
              if (item.p) cleanMap[item.p] = item.d || '';
          });
          setPartsMap(cleanMap);
      } else {
          setDoc(doc(db, 'settings', 'parts'), { data: [] });
      }
    });

    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, BOMComponent[]> = {};
          raw.forEach((item: any) => {
              if (item.parent && item.child) {
                  if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                  cleanMap[item.parent].push({ child: item.child, consumption: item.q || 0 });
              }
          });
          setBomMap(cleanMap);
      } else {
          setDoc(doc(db, 'settings', 'bom'), { data: [] });
      }
    });

    const unsubBreaks = onSnapshot(doc(db, 'settings', 'breaks'), (s) => {
      if (s.exists()) {
        setBreakSchedules(s.data().data || []);
      } else {
        setDoc(doc(db, 'settings', 'breaks'), { data: [] });
      }
    });

    return () => { unsubParts(); unsubBOM(); unsubBreaks(); };
  }, []);

  useEffect(() => { return onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem)))); }, []);
  useEffect(() => { return onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem)))); }, []);

  useEffect(() => { 
      return onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), async (s) => {
          if (s.empty && !s.metadata.fromCache) {
               const defaults = ['VYKLÁDKA', 'NAKLÁDKA', 'ZASKLADNENIE', 'INTERNÝ PRESUN'];
               const batch = writeBatch(db);
               defaults.forEach(op => batch.set(doc(collection(db, 'logistics_operations')), { value: op, standardTime: 0, distancePx: 0 }));
               await batch.commit();
          } else {
              const ops = s.docs.map(d => ({id:d.id, ...d.data()} as DBItem));
              setLogisticsOperations(ops);
          }
      }); 
  }, []);

  // Single source of truth pre logistické sektory (Collection model)
  useEffect(() => {
    return onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
      const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
      setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0) || (a.name || '').localeCompare(b.name || '')));
    });
  }, []);

  useEffect(() => { const q = query(collection(db, 'part_requests')); return onSnapshot(q, s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest)))); }, []);
  useEffect(() => { const q = query(collection(db, 'bom_requests')); return onSnapshot(q, s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest)))); }, []);

  useEffect(() => { 
      if (!isAuthenticated || !currentUser) return;
      const q = query(collection(db, 'notifications'), where('targetUser', '==', currentUser)); 
      return onSnapshot(q, s => setNotifications(s.docs.map(d => ({id:d.id, ...d.data()} as Notification)))); 
  }, [isAuthenticated, currentUser]);

  useEffect(() => { 
      const q = query(collection(db, 'system_breaks')); 
      return onSnapshot(q, s => {
          const breaks = s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak));
          setSystemBreaks(breaks);
      }); 
  }, []);

  // OPRAVA LOGIKY DETEKCIE PRESTÁVKY
  const checkBreakStatus = useCallback(() => {
      const now = new Date();
      const currentHHMM = now.getHours().toString().padStart(2, '0') + ':' + 
                          now.getMinutes().toString().padStart(2, '0');

      // 1. Plánované prestávky z nastavení (Bucket settings/breaks)
      const isScheduledActive = breakSchedules.some(b => 
          currentHHMM >= b.startTime && currentHHMM <= b.endTime
      );

      // 2. Manuálne spustené prestávky (Collection system_breaks)
      const isManualActive = systemBreaks.some(b => b.isActive);

      setIsBreakActive(isScheduledActive || isManualActive);
  }, [breakSchedules, systemBreaks]);

  useEffect(() => {
      checkBreakStatus(); // Prvotná kontrola
      const interval = setInterval(checkBreakStatus, 30000); // Kontrola každých 30s
      return () => clearInterval(interval);
  }, [checkBreakStatus]);

  const handleLogin = (u: string, r: any) => { 
    setIsAuthenticated(true); 
    setCurrentUser(u); 
    setCurrentUserRole(r); 
    localStorage.setItem('app_user', u); 
    localStorage.setItem('app_role', r); 
    if (r !== 'ADMIN' || !systemConfig.adminLockEnabled) {
      setIsUnlocked(true);
      sessionStorage.setItem('app_unlocked', 'true');
    }
  };

  const handleAddUser = async (u: UserData) => { await addDoc(collection(db, 'users'), { ...u, canExportAnalytics: u.canExportAnalytics || false }); };
  const handleUpdatePassword = async (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {password: p}); } };
  const handleUpdateNickname = async (u: string, n: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {nickname: n}); } };
  const handleUpdateExportPermission = async (u: string, canExport: boolean) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {canExportAnalytics: canExport}); } };
  const handleUpdateUserRole = async (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {role: r}); } };
  const handleDeleteUser = async (u: string) => { const user = users.find(us => us.username === u); if(user) { await deleteDoc(doc(db,'users', user.id!)); } };

  const handleAddPart = async (v: string, desc?: string) => { 
    const updatedMap = { ...partsMap, [v.trim()]: desc || '' };
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleBatchAddParts = async (vs: string[]) => { 
    const updatedMap = { ...partsMap };
    vs.forEach(line => {
      const [val, desc] = line.split(';');
      if (val) updatedMap[val.trim()] = desc ? desc.trim() : '';
    });
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleDeletePart = async (partValue: string) => { 
    const updatedMap = { ...partsMap };
    delete updatedMap[partValue];
    const dataArray = Object.entries(updatedMap).map(([p, d]) => ({ p, d }));
    await setDoc(doc(db, 'settings', 'parts'), { data: dataArray });
  };
  const handleDeleteAllParts = async () => { 
    await setDoc(doc(db, 'settings', 'parts'), { data: [] }); 
  };

  const handleAddBOMItem = async (p: string, c: string, q: number) => { 
    const updatedMap = { ...bomMap };
    const current = updatedMap[p] || [];
    updatedMap[p] = [...current.filter(item => item.child !== c), { child: c, consumption: Number(q.toFixed(5)) }];
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([parent, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleBatchAddBOMItems = async (vs: string[]) => { 
    const updatedMap = { ...bomMap };
    vs.forEach(l => {
      const [p, c, q] = l.split(';');
      if (p && c && q) {
        const parent = p.trim();
        if (!updatedMap[parent]) updatedMap[parent] = [];
        const sanitizedQty = Number(parseFloat(q.trim().replace(',', '.')).toFixed(5));
        updatedMap[parent] = [...updatedMap[parent].filter(x => x.child !== c.trim()), { child: c.trim(), consumption: sanitizedQty }];
      }
    });
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([parent, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleDeleteBOMItem = async (parent: string, child: string) => { 
    const updatedMap = { ...bomMap };
    if (updatedMap[parent]) {
        updatedMap[parent] = updatedMap[parent].filter(item => item.child !== child);
        if (updatedMap[parent].length === 0) delete updatedMap[parent];
    }
    const dataArray: any[] = [];
    Object.entries(updatedMap).forEach(([pKey, components]) => {
        (components as BOMComponent[]).forEach(comp => {
            dataArray.push({ parent: pKey, child: comp.child, q: comp.consumption });
        });
    });
    await setDoc(doc(db, 'settings', 'bom'), { data: dataArray });
  };
  const handleDeleteAllBOMItems = async () => { 
    await setDoc(doc(db, 'settings', 'bom'), { data: [] }); 
  };

  const handleAddWorkplace = async (v: string, t?: number, x?: number, y?: number) => { 
    await addDoc(collection(db, 'workplaces'), { value: v, standardTime: t || 0, coordX: x || 0, coordY: y || 0 }); 
  };
  const handleUpdateWorkplace = async (id: string, updates: Partial<DBItem>) => { 
    await updateDoc(doc(db, 'workplaces', id), updates); 
  };
  const handleBatchAddWorkplaces = async (vs: string[]) => { const b=writeBatch(db); vs.forEach(l=>{const [v,t]=l.split(';'); if(v) b.set(doc(collection(db,'workplaces')), {value:v.trim(), standardTime: parseInt(t)||0, coordX: 0, coordY: 0})}); await b.commit(); };
  const handleDeleteWorkplace = async (id: string) => { await deleteDoc(doc(db,'workplaces',id)); };
  const handleDeleteAllWorkplaces = async () => { const s=await getDocs(collection(db,'workplaces')); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); };
  const handleAddMissingReason = async (v: string) => { await addDoc(collection(db,'missing_reasons'), {value:v}); };
  const handleDeleteMissingReason = async (id: string) => { await deleteDoc(doc(db,'missing_reasons',id)); };
  const handleAddLogisticsOperation = async (v: string, t?: number, d?: number) => { await addDoc(collection(db,'logistics_operations'), {value:v, standardTime: t || 0, distancePx: d || 0 }); };
  const handleUpdateLogisticsOperation = async (id: string, updates: Partial<DBItem>) => { await updateDoc(doc(db, 'logistics_operations', id), updates); };
  const handleDeleteLogisticsOperation = async (id: string) => { await deleteDoc(doc(db,'logistics_operations',id)); };

  const handleAddMapSector = async (name: string, x: number, y: number, color?: string) => { 
    await addDoc(collection(db, 'map_sectors'), { 
      name: name.toUpperCase(), 
      coordX: x, 
      coordY: y, 
      color: color || 'slate', 
      order: mapSectors.length 
    });
  };
  const handleDeleteMapSector = async (id: string) => { 
    await deleteDoc(doc(db, 'map_sectors', id));
  };
  const handleUpdateMapSector = async (id: string, updates: Partial<MapSector>) => { 
    await updateDoc(doc(db, 'map_sectors', id), updates);
  };

  const handleDeleteMissingItem = (id: string) => deleteDoc(doc(db,'tasks',id));

  const handleAddBreakSchedule = async (s: string, e: string) => { 
    const newBreak = { id: crypto.randomUUID(), name: 'Prestávka', startTime: s, endTime: e };
    await updateDoc(doc(db, 'settings', 'breaks'), {
      data: arrayUnion(newBreak)
    });
  };
  const handleDeleteBreakSchedule = async (id: string) => { 
    const br = breakSchedules.find(b => b.id === id);
    if (br) {
      await updateDoc(doc(db, 'settings', 'breaks'), {
        data: arrayRemove(br)
      });
    }
  };

  const handleRequestBOM = async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApproveBOMRequest = (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id));
  const handleRejectBOMRequest = (id: string) => deleteDoc(doc(db,'bom_requests',id));
  const handleAddRole = async (n:string) => { const nameUpper = n.toUpperCase(); if (roles.some(r => r.name === nameUpper)) { alert("Rola s týmto názvom už existuje!"); return; } await addDoc(collection(db,'roles'), {name:nameUpper, isSystem:false}); };
  const handleDeleteRole = async (id:string) => { await deleteDoc(doc(db,'roles',id)); const s=await getDocs(query(collection(db,'permissions'), where('roleId','==',id))); const b=writeBatch(db); s.forEach(d=>b.delete(d.ref)); await b.commit(); };
  const handleUpdatePermission = async (pid:string, rname:string, has:boolean) => { const r=roles.find(ro=>ro.name===rname); if(!r)return; if(has) await addDoc(collection(db,'permissions'), {roleId:r.id, permissionName:pid}); else { const p=permissions.find(perm=>perm.roleId===r.id && perm.permissionName===pid); if(p) await deleteDoc(doc(db,'permissions',p.id)); } };
  const handleVerifyAdminPassword = (password: string) => { return users.some(u => u.role === 'ADMIN' && u.password === password); };
  const handleRequestNewPart = async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; };
  const handleApprovePartRequest = (req: PartRequest) => { handleAddPart(req.partNumber); deleteDoc(doc(db,'part_requests',req.id)); };
  const handleRejectPartRequest = (id: string) => deleteDoc(doc(db,'part_requests',id));

  const handleAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics: boolean = false, note?: string) => {
    let finalUnit = unit;
    const description = partsMap[pn];
    if (description) {
        if (description.includes('S0001S')) finalUnit = 'pcs';
        else if (description.includes('S0002S')) finalUnit = 'boxes';
        else if (description.includes('S0003S')) finalUnit = 'pallet';
    }
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(finalUnit === 'boxes') fQty = `${qty} box`; 
    if(finalUnit === 'pallet') fQty = `${qty} pal`;
    let text = `${formattedDate} / ${pn}`; 
    if (wp) text += ` / ${wp}`; 
    if (fQty) text += ` / Počet: ${fQty}`;
    if (note) text += ` / Pozn: ${note}`;
    let finalStandardTime = 0;
    if (!isLogistics) {
        const wpObj = workplaces.find(w => w.value === wp);
        finalStandardTime = wpObj?.standardTime || 0;
        if (finalUnit === 'pallet' && qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) finalStandardTime = Math.round(finalStandardTime * numericQty);
        }
    } else {
        const opObj = logisticsOperations.find(op => op.value === wp); 
        finalStandardTime = opObj?.standardTime || 0;
        if (qty) {
            const numericQty = parseFloat(qty.replace(',', '.'));
            if (!isNaN(numericQty) && numericQty > 0) finalStandardTime = Math.round(finalStandardTime * numericQty);
        }
    }
    const isInventoryTask = pn === "Počítanie zásob";
    const now = Date.now();
    await addDoc(collection(db, 'tasks'), { text, partNumber: pn, workplace: wp, quantity: qty, quantityUnit: finalUnit, standardTime: finalStandardTime, isDone:false, priority:prio, createdAt:now, createdBy:currentUser, isLogistics, isProduction: !isLogistics, isInProgress: isInventoryTask, inProgressBy: isInventoryTask ? currentUser : null, startedAt: isInventoryTask ? now : null, note: note || null, expireAt: now + (90 * 24 * 60 * 60 * 1000) });
  };

  const handleUpdateTask = async (id: string, updates: Partial<Task>) => { await updateDoc(doc(db, 'tasks', id), updates); };

  const handleToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        if (!t.isDone) {
            if (t.isLogistics) {
                await updateDoc(doc(db, 'tasks', id), { 
                    isDone: true, 
                    status: 'completed', 
                    completionTime: new Date().toLocaleTimeString('sk-SK'), 
                    completedBy: currentUser, 
                    completedAt: Date.now(), 
                    isInProgress: false, 
                    inProgressBy: null, 
                    isBlocked: false, 
                    isManualBlocked: false, 
                    isAuditInProgress: false, 
                    auditBy: null
                });
                return;
            }
            setFinishingTaskId(id);
            setShowSectorModal(true);
            return;
        }
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false, isAuditInProgress: false, auditBy: null, pickedFromSectorId: deleteField() });
    }
  };

  const confirmTaskCompletion = async (sectorId: string) => {
    if (!finishingTaskId) return;
    const id = finishingTaskId;
    await updateDoc(doc(db, 'tasks', id), { 
        isDone: true, 
        status: 'completed', 
        completionTime: new Date().toLocaleTimeString('sk-SK'), 
        completedBy: currentUser, 
        completedAt: Date.now(), 
        isInProgress: false, 
        inProgressBy: null, 
        isBlocked: false, 
        isManualBlocked: false, 
        isAuditInProgress: false, 
        auditBy: null,
        pickedFromSectorId: sectorId
    });
    setShowSectorModal(false);
    setFinishingTaskId(null);
  };

  const handleMarkAsIncorrect = async (id: string) => updateDoc(doc(db,'tasks',id), { isDone:true, status:'incorrectly_entered', completionTime:new Date().toLocaleTimeString('sk-SK'), completedBy:currentUser, completedAt:Date.now(), isInProgress:false, inProgressBy:null, isBlocked:false, isManualBlocked: false, isAuditInProgress: false, auditBy: null });
  const handleSetInProgress = async (id: string) => { const t = tasks.find(x=>x.id===id); if(t) updateDoc(doc(db,'tasks',id), { isInProgress:!t.isInProgress, inProgressBy:!t.isInProgress?currentUser:null, startedAt:(!t.isInProgress && !t.startedAt)?Date.now():t.startedAt }); };
  const handleAddNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleAddLogisticsNote = (id:string, n:string) => updateDoc(doc(db,'tasks',id), {note:n});
  const handleReleaseTask = (id:string) => updateDoc(doc(db,'tasks',id), {isInProgress:false, inProgressBy:null});
  const handleEditTask = (id:string, txt:string, prio?:PriorityLevel) => updateDoc(doc(db,'tasks',id), {text:txt, priority:prio});
  const handleDeleteTask = (id:string) => deleteDoc(doc(db,'tasks',id));
  const handleToggleMissing = async (id:string, reason?:string) => { 
      const t=tasks.find(x=>x.id===id); 
      if(t) {
          const isMissing = !t.isMissing;
          await updateDoc(doc(db,'tasks',id), { 
              isMissing, 
              missingReportedBy: isMissing?currentUser:null, 
              missingReason: isMissing?(reason||'Iné'):null, 
              isInProgress: false, 
              inProgressBy: null, 
              isBlocked: false, 
              blockedBy: null, 
              searchedBy: isMissing ? (t.searchedBy || null) : null,
              isManualBlocked: false, 
              isAuditInProgress: false, 
              auditBy: null 
          });
          if (isMissing && t.createdBy && t.createdBy !== currentUser) {
              await addDoc(collection(db, 'notifications'), { 
                  partNumber: t.partNumber || 'Unknown', 
                  reason: reason || 'Iné', 
                  reportedBy: currentUser, 
                  targetUser: t.createdBy, 
                  timestamp: Date.now() 
              });
          }
      } 
  };
  const handleClearNotification = (id: string) => deleteDoc(doc(db, 'notifications', id));
  const handleToggleBlock = async (id: string) => {
      const t=tasks.find(x=>x.id===id);
      if(t) {
          const isBlocked = !t.isBlocked;
          const hist = t.inventoryHistory ? [...t.inventoryHistory] : [];
          if(isBlocked) hist.push({start:Date.now()}); else { const last=hist[hist.length-1]; if(last && !last.end) last.end=Date.now(); }
          const u = users.find(x => x.username === currentUser);
          const nickname = u?.nickname || currentUser;
          updateDoc(doc(db,'tasks',id), { 
              isBlocked, 
              blockedBy: isBlocked ? currentUser : null, 
              searchedBy: isBlocked ? nickname : (t.searchedBy || null),
              inventoryHistory:hist 
          });
      }
  };
  const handleToggleManualBlock = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) {
          const newState = !t.isManualBlocked;
          await updateDoc(doc(db, 'tasks', id), { isManualBlocked: newState, createdAt: !newState ? Date.now() : t.createdAt, isInProgress: false, inProgressBy: null });
      }
  };
  const handleExhaustSearch = async (id: string) => {
      await updateDoc(doc(db, 'tasks', id), { searchExhausted: true, isBlocked: false, blockedBy: null });
  };
  const handleStartAudit = async (id: string) => { 
      const u = users.find(x => x.username === currentUser);
      const name = (u?.nickname || currentUser);
      await updateDoc(doc(db, 'tasks', id), { isAuditInProgress: true, auditBy: name }); 
  };
  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
      const t = tasks.find(x => x.id === id);
      if (!t) return;
      const u = users.find(x => x.username === currentUser);
      const displayName = (u?.nickname || currentUser).toUpperCase();
      const statusLabel = result === 'found' ? 'OK' : 'CHÝBA';
      const badgeText = `AUDIT ${statusLabel}: ${note} (${displayName})`;
      const auditData = { 
          auditedBy: currentUser, 
          auditedAt: Date.now(), 
          auditResult: result === 'found' ? 'OK' : 'NOK', 
          auditNote: note, 
          isAuditInProgress: false, 
          auditBy: null, 
          auditFinalBadge: badgeText 
      };
      if (result === 'found') {
          await updateDoc(doc(db, 'tasks', id), { ...auditData, isMissing: false });
      } else {
          await updateDoc(doc(db, 'tasks', id), { 
              ...auditData, 
              isDone: true, 
              status: 'completed', 
              completionTime: new Date().toLocaleTimeString('sk-SK'), 
              completedBy: currentUser, 
              completedAt: Date.now() 
          });
      }
      if (t.createdBy && t.createdBy !== currentUser) {
          await addDoc(collection(db, 'notifications'), { partNumber: t.partNumber || 'N/A', reason: `AUDIT DOKONČENÝ (${statusLabel}): ${note}`, reportedBy: currentUser, targetUser: t.createdBy, timestamp: Date.now() });
      }
  };

  const handleDailyClosing = async () => {
      const q = query(collection(db, 'tasks'), where('isDone', '==', true));
      const s = await getDocs(q);
      if (s.empty) return { success: true, count: 0 };

      // KOMPLETNÝ PRENOS VŠETKÝCH PARAMETROV (FULL SPREAD)
      const doneTasks = s.docs.map(d => ({ 
          ...d.data(), 
          id: d.id, 
          archivedAt: Date.now() 
      }));

      const draftRef = doc(db, 'settings', 'draft');
      const draftSnap = await getDoc(draftRef);
      if (!draftSnap.exists()) {
          await setDoc(draftRef, { data: doneTasks });
      } else {
          await updateDoc(draftRef, { data: arrayUnion(...doneTasks) });
      }

      const batch = writeBatch(db);
      s.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
      return { success: true, count: s.size };
  };

  const handleWeeklyClosing = async () => {
      const draftRef = doc(db, 'settings', 'draft');
      const draftSnap = await getDoc(draftRef);
      if (!draftSnap.exists() || !draftSnap.data().data?.length) return { success: true, count: 0 };

      // KOMPLETNÝ PRENOS VŠETKÝCH PARAMETROV Z DRAFTU DO ŠANÓNU
      const tasksToSanon = draftSnap.data().data;
      const now = new Date();
      const year = now.getFullYear();
      const firstDayOfYear = new Date(year, 0, 1);
      const pastDaysOfYear = (now.getTime() - firstDayOfYear.getTime()) / 86400000;
      const weekNum = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7);
      const sanonId = `${year}_${weekNum}`;

      await setDoc(doc(db, 'sanony', sanonId), { 
          tasks: tasksToSanon, 
          archivedAt: Date.now(),
          year: year,
          week: weekNum
      });

      await updateDoc(draftRef, { data: [] });

      return { success: true, count: tasksToSanon.length, sanon: sanonId };
  };

  const handleArchiveTasks = async () => { return await handleDailyClosing(); };
  const fetchArchivedTasks = async () => {
      const snap = await getDoc(doc(db, 'settings', 'draft'));
      return (snap.exists() ? snap.data().data : []) as Task[];
  };

  const handleGetDocCount = useCallback(async () => {
      const snap = await getCountFromServer(collection(db, 'tasks'));
      return snap.data().count;
  }, []);
  const handlePurgeOldTasks = useCallback(async () => {
      const ninetyDaysAgo = Date.now() - (90 * 24 * 60 * 60 * 1000);
      const q = query(collection(db, 'tasks'), where('createdAt', '<', ninetyDaysAgo), limit(500));
      const snap = await getDocs(q);
      if (snap.empty) return 0;
      const batch = writeBatch(db);
      snap.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
      return snap.size;
  }, []);
  const handleExportTasksJSON = useCallback(async () => {
      const snap = await getDocs(query(collection(db, 'tasks'), limit(1000)));
      const data = snap.docs.map(d => ({ id: d.id, ...d.data() }));
      const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `backup_tasks_${new Date().toISOString().slice(0,10)}.json`;
      a.click();
  }, []);
  const partsArray = Object.entries(partsMap).map(([value, description]) => ({ id: value, value, description }));

  const LockScreen = ({ onUnlock }: { onUnlock: (key: string) => void }) => {
    const [input, setInput] = useState('');
    return (
      <div className="fixed inset-0 z-[10000] bg-slate-950 flex items-center justify-center p-4">
        <div className="bg-gray-800 border-2 border-slate-700 p-10 rounded-[2rem] shadow-2xl w-full max-sm text-center">
          <div className="w-20 h-20 bg-blue-600/20 rounded-full flex items-center justify-center mx-auto mb-8 border border-blue-500/50">
            <svg xmlns="http://www.w3.org/2000/svg" className="w-10 h-10 text-[#4169E1]" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
            </svg>
          </div>
          <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-2">SYSTÉM UZAMKNUTÝ</h2>
          <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mb-8">ZADAJTE BEZPEČNOSTNÝ KĽÚČ</p>
          <input 
            type="password" 
            autoFocus
            value={input}
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && onUnlock(input)}
            placeholder="••••"
            className="w-full h-16 bg-slate-900 border-2 border-slate-700 rounded-xl text-center text-3xl font-black text-white focus:outline-none focus:ring-2 focus:ring-[#4169E1] transition-all mb-6"
          />
          <button 
            onClick={() => onUnlock(input)}
            className="w-full py-4 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black rounded-xl uppercase tracking-widest text-xs border-2 border-blue-500 shadow-xl transition-all active:scale-95"
          >
            ODOMKNÚŤ SYSTÉM
          </button>
        </div>
      </div>
    );
  };

  const handleToggleAdminLock = (val: boolean) => {
    handleUpdateSystemConfig({ adminLockEnabled: val });
  };

  return (
    <div className={`min-h-screen bg-gray-900 flex flex-col ${!isAuthenticated ? 'items-center justify-center' : ''}`}>
      {!isAuthenticated ? (
        <LoginScreen onLoginSuccess={handleLogin} users={users} systemConfig={systemConfig} />
      ) : (currentUserRole === 'ADMIN' && systemConfig.adminLockEnabled && !isUnlocked) ? (
        <LockScreen onUnlock={handleUnlockAttempt} />
      ) : (
        <PartSearchScreen 
          currentUser={currentUser} currentUserRole={currentUserRole} onLogout={handleLogout}
          tasks={tasks} onAddTask={handleAddTask} onToggleTask={handleToggleTask} onEditTask={handleEditTask} onMarkAsIncorrect={handleMarkAsIncorrect} onAddNote={handleAddNote} onReleaseTask={handleReleaseTask}
          onDeleteTask={handleDeleteTask}
          onUpdateTask={handleUpdateTask}
          onToggleMissing={handleToggleMissing} onSetInProgress={handleSetInProgress} onToggleBlock={handleToggleBlock} onToggleManualBlock={handleToggleManualBlock}
          onExhaustSearch={handleExhaustSearch}
          onStartAudit={handleStartAudit} onFinishAudit={handleFinishAudit}
          users={users} onAddUser={handleAddUser} onUpdatePassword={handleUpdatePassword} onUpdateNickname={handleUpdateNickname} onUpdateExportPermission={handleUpdateExportPermission} onUpdateUserRole={handleUpdateUserRole} onDeleteUser={handleDeleteUser}
          parts={partsArray} workplaces={workplaces} missingReasons={missingReasons} logisticsOperations={logisticsOperations}
          mapSectors={mapSectors} onAddMapSector={handleAddMapSector} onDeleteMapSector={handleDeleteMapSector} onUpdateMapSector={handleUpdateMapSector}
          onAddPart={handleAddPart} onBatchAddParts={handleBatchAddParts} onDeletePart={handleDeletePart} onDeleteAllParts={handleDeleteAllParts}
          onAddWorkplace={handleAddWorkplace} onUpdateWorkplace={handleUpdateWorkplace} onBatchAddWorkplaces={handleBatchAddWorkplaces} onDeleteWorkplace={handleDeleteWorkplace} onDeleteAllWorkplaces={handleDeleteAllWorkplaces}
          onAddMissingReason={handleAddMissingReason} onDeleteMissingReason={handleDeleteMissingReason}
          onAddLogisticsOperation={handleAddLogisticsOperation} onUpdateLogisticsOperation={handleUpdateLogisticsOperation} onDeleteLogisticsOperation={handleDeleteLogisticsOperation}
          partRequests={partRequests} onRequestPart={handleRequestNewPart} onApprovePartRequest={handleApprovePartRequest} onRejectPartRequest={handleRejectPartRequest}
          onArchiveTasks={handleArchiveTasks} 
          onDailyClosing={handleDailyClosing}
          onWeeklyClosing={handleWeeklyClosing}
          onFetchArchivedTasks={fetchArchivedTasks}
          onDeleteMissingItem={handleDeleteMissingItem}
          onGetDocCount={handleGetDocCount}
          onPurgeOldTasks={handlePurgeOldTasks}
          onExportTasksJSON={handleExportTasksJSON}
          breakSchedules={breakSchedules} systemBreaks={systemBreaks} isBreakActive={isBreakActive} onAddBreakSchedule={handleAddBreakSchedule} onDeleteBreakSchedule={handleDeleteBreakSchedule}
          bomMap={bomMap} bomRequests={bomRequests} onAddBOMItem={handleAddBOMItem} onBatchAddBOMItems={handleBatchAddBOMItems} onDeleteBOMItem={handleDeleteBOMItem} onDeleteAllBOMItems={handleDeleteAllBOMItems} onRequestBOM={handleRequestBOM} onApproveBOMRequest={handleApproveBOMRequest} onRejectBOMRequest={handleRejectBOMRequest} roles={roles} permissions={permissions} onAddRole={handleAddRole} onDeleteRole={handleDeleteRole} onUpdatePermission={handleUpdatePermission}
          onVerifyAdminPassword={handleVerifyAdminPassword}
          notifications={notifications} onClearNotification={handleClearNotification}
          installPrompt={deferredPrompt} onInstallApp={handleInstallApp}
          systemConfig={systemConfig} onUpdateSystemConfig={handleUpdateSystemConfig}
          dbLoadWarning={dbLoadWarning} 
          onUpdateAdminKey={handleUpdateAdminKey}
          onToggleAdminLock={handleToggleAdminLock}
        />
      )}

      {showSectorModal && (
        <div className="fixed inset-0 z-[11000] bg-black/90 backdrop-blur-lg flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-gray-800 border-2 border-teal-500 p-8 rounded-[2rem] shadow-2xl w-[95%] md:max-w-4xl text-center ring-4 ring-teal-500/10">
            <h2 className="text-2xl font-black text-white uppercase tracking-tighter mb-10 leading-tight">ODKIAL SI BRAL TOVAR?<br/><span className="text-teal-400 text-sm tracking-widest">(VYBER MIESTO)</span></h2>
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
              {mapSectors.length > 0 ? mapSectors.map(s => (
                <button 
                  key={s.id} 
                  onClick={() => confirmTaskCompletion(s.id)}
                  className={`py-8 border-2 text-white font-black rounded-2xl uppercase tracking-normal text-2xl transition-all active:scale-95 shadow-xl ${s.color ? colorMap[s.color] : colorMap.slate}`}
                >
                  {s.name}
                </button>
              )) : (
                <div className="col-span-2 py-4 text-slate-500 italic text-lg">Žiadne sektory nie sú definované v nastaveniach.</div>
              )}
            </div>
            <button 
              onClick={() => { setShowSectorModal(false); setFinishingTaskId(null); }}
              className="mt-6 text-slate-500 font-black uppercase tracking-widest text-sm hover:text-slate-300 transition-colors"
            >
              SPÄŤ NA ZOZNAM
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useMemo, useState, useEffect } from 'react';
import { db } from '../../../firebase';
import { doc, getDoc } from 'firebase/firestore';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, UserData } from '../../../App';
import { useLanguage } from '../../LanguageContext';
import AnalyticsExportPanel from './AnalyticsExportPanel';
import HighRunnerSection from './HighRunnerSection';
import HourlyChartSection from './HourlyChartSection';
import QualityAuditSection from './QualityAuditSection';
import WorkerDetailModal from './WorkerDetailModal';
import DrivingMetrics from './DrivingMetrics';

declare var XLSX: any;

interface AnalyticsTabProps {
  tasks: Task[];
  onFetchArchivedTasks: () => Promise<Task[]>;
  systemBreaks: SystemBreak[];
  resolveName: (username?: string | null) => string;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
  // Pridané props pre kontrolu exportu
  users: UserData[];
  currentUser: string;
  currentUserRole: string;
}

type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
type ShiftFilter = 'ALL' | 'MORNING' | 'AFTERNOON';
type SourceFilter = 'ALL' | 'PRODUCTION' | 'LOGISTICS';

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ 
  tasks: _liveTasks, onFetchArchivedTasks, systemBreaks, resolveName, mapSectors, workplaces, systemConfig, logisticsOperations,
  users, currentUser, currentUserRole 
}) => {
  const [filterMode, setFilterMode] = useState<FilterMode>('TODAY');
  const [shiftFilter, setShiftFilter] = useState<ShiftFilter>('ALL');
  const [sourceFilter, setSourceFilter] = useState<SourceFilter>('ALL');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [archivedTasks, setArchivedTasks] = useState<Task[]>([]);
  const [isLoadingArchive, setIsLoadingArchive] = useState(false);
  const [selectedWorkerData, setSelectedWorkerData] = useState<{ name: string; tasks: Task[] } | null>(null);
  const { t, language } = useLanguage();

  // STRIKTNÁ LOGIKA: Admin vidí export vždy, USER len ak má príznak canExportAnalytics v DB
  const canExport = useMemo(() => {
    return currentUserRole === 'ADMIN' || (users.find(u => u.username === currentUser)?.canExportAnalytics === true);
  }, [currentUser, currentUserRole, users]);

  const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;
  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];

  const tasks = useMemo(() => archivedTasks, [archivedTasks]);

  useEffect(() => {
    const load = async () => {
      if (isLoadingArchive) return;
      setIsLoadingArchive(true);
      try {
        const results: Task[] = [];
        const startOfMonthTs = new Date(now.getFullYear(), now.getMonth(), 1).getTime();

        // 1. Načítanie Draftu (aktuálny týždeň)
        const draftSnap = await getDoc(doc(db, 'settings', 'draft'));
        if (draftSnap.exists()) {
            const draftData = draftSnap.data().data || [];
            draftData.forEach((t: any) => {
                if (t.completedAt >= startOfMonthTs) results.push(t);
            });
        }

        // 2. Načítanie relevantných šanónov (posledných 5 týždňov pre pokrytie mesiaca)
        const currentYear = now.getFullYear();
        const firstDayOfYear = new Date(currentYear, 0, 1);
        const pastDaysOfYear = (now.getTime() - firstDayOfYear.getTime()) / 86400000;
        const currentWeekNum = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7);

        const weeksToCheck = [currentWeekNum, currentWeekNum - 1, currentWeekNum - 2, currentWeekNum - 3, currentWeekNum - 4];
        const sanonPromises = weeksToCheck.filter(w => w > 0).map(w => getDoc(doc(db, 'sanony', `${currentYear}_${w}`)));
        const sanonSnaps = await Promise.all(sanonPromises);

        sanonSnaps.forEach(snap => {
            if (snap.exists()) {
                const tasksInSanon = snap.data().tasks || [];
                tasksInSanon.forEach((t: any) => {
                    if (t.completedAt >= startOfMonthTs) results.push(t);
                });
            }
        });

        setArchivedTasks(results);
      } catch (err) {
        console.error("Archive fetch error:", err);
      } finally {
        setIsLoadingArchive(false);
      }
    };
    load();
  }, [filterMode]);

  const filteredTasks = useMemo(() => {
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    return tasks.filter(task => {
      if (sourceFilter === 'PRODUCTION' && task.isLogistics) return false;
      if (sourceFilter === 'LOGISTICS' && !task.isLogistics) return false;

      const referenceTime = task.completedAt || task.createdAt;
      if (!referenceTime) return false;

      const taskDate = new Date(referenceTime);
      const taskDayStart = new Date(taskDate.getFullYear(), taskDate.getMonth(), taskDate.getDate());

      let passesTimeFilter = false;
      switch (filterMode) {
        case 'TODAY': passesTimeFilter = taskDayStart.getTime() === todayStart.getTime(); break;
        case 'YESTERDAY':
          const yesterdayStart = new Date(todayStart);
          yesterdayStart.setDate(yesterdayStart.getDate() - 1);
          passesTimeFilter = taskDayStart.getTime() === yesterdayStart.getTime();
          break;
        case 'WEEK': passesTimeFilter = referenceTime >= (todayStart.getTime() - (7 * 86400000)); break;
        case 'MONTH': passesTimeFilter = taskDate.getMonth() === now.getMonth() && taskDate.getFullYear() === now.getFullYear(); break;
        case 'CUSTOM':
            if (!customStart || !customEnd) return false;
            const s = new Date(customStart).getTime();
            const e = new Date(customEnd).getTime() + 86399999;
            passesTimeFilter = referenceTime >= s && referenceTime <= e;
            break;
        default: passesTimeFilter = true;
      }

      if (!passesTimeFilter) return false;
      if (shiftFilter === 'ALL') return true;

      const hours = taskDate.getHours();
      if (shiftFilter === 'MORNING') return hours >= 4 && hours < 14;
      if (shiftFilter === 'AFTERNOON') return hours >= 14 && hours < 24;
      return true;
    });
  }, [tasks, filterMode, shiftFilter, sourceFilter, customStart, customEnd]);

  const stats = useMemo(() => {
    const workplacesMap: Record<string, { load: number, pal: number, taskRequests: number, totalTasks: number }> = {};
    const hourlyStatsMap: Record<number, { production: number, logistics: number }> = {};
    const missingPartsMap: Record<string, number> = {};
    const workerStatsMap: Record<string, any> = {};

    for (let i = 0; i < 24; i++) hourlyStatsMap[i] = { production: 0, logistics: 0 };
    let realErrorsCount = 0, totalAuditedMissing = 0, falseAlarmsCount = 0, grandTotalExecutionTime = 0;
    let globalFullDist = 0, globalEmptyDist = 0, globalRides = 0;

    const performanceTasks = filteredTasks.filter(t => t.status !== 'incorrectly_entered' && t.auditResult !== 'NOK');
    performanceTasks.forEach(task => {
      const qtyVal = parseFloat((task.quantity || '0').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      const hour = (task.completedAt || task.createdAt) ? new Date(task.completedAt || task.createdAt!).getHours() : -1;

      if (task.isMissing === true) {
        if (task.partNumber) missingPartsMap[task.partNumber] = (missingPartsMap[task.partNumber] || 0) + 1;
        if (task.auditResult) {
          totalAuditedMissing++;
          if (task.auditResult === 'NOK') realErrorsCount++;
          else falseAlarmsCount++;
        }
      }

      if (task.isDone && task.completedBy) {
        const worker = task.completedBy;
        if (!workerStatsMap[worker]) {
            workerStatsMap[worker] = { username: worker, name: resolveName(worker), count: 0, totalVolume: 0, totalExecutionMs: 0, totalStandardMin: 0, totalReactionMs: 0, reactionCount: 0, missingReported: 0, realErrors: 0, uniqueDays: new Set(), totalFullDist: 0, totalEmptyDist: 0, totalRides: 0 };
        }
        const ws = workerStatsMap[worker];
        let validatedTrips = 0, oneWayD = 0;

        if (task.isLogistics) {
            const logOp = logisticsOperations.find(o => o.value === task.workplace);
            if (logOp?.distancePx) {
                oneWayD = logOp.distancePx;
                const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                validatedTrips = Math.min(!isNaN(qtyVal) ? Math.max(1, Math.floor(qtyVal)) : 1, Math.max(1, Math.round(((durationMs/1000)*VZV_SPEED_MPS)/(2*oneWayD))));
            }
        } else if (task.pickedFromSectorId && task.workplace) {
            const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
            const wp = workplaces.find(w => w.value === task.workplace);
            if (sector && wp) {
                oneWayD = Math.sqrt(Math.pow(wp.coordX!-sector.coordX,2)+Math.pow(wp.coordY!-sector.coordY,2))/10;
                const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                validatedTrips = Math.min(!isNaN(qtyVal) ? Math.max(1, Math.floor(qtyVal)) : 1, Math.max(1, Math.round(((durationMs/1000)*VZV_SPEED_MPS)/(2*oneWayD))));
            }
        }

        if (validatedTrips > 0) {
            globalRides += validatedTrips; ws.totalRides += validatedTrips;
            globalFullDist += validatedTrips * oneWayD; ws.totalFullDist += validatedTrips * oneWayD;
            globalEmptyDist += validatedTrips * oneWayD; ws.totalEmptyDist += validatedTrips * oneWayD;
        }
        ws.count += 1; ws.totalVolume += loadPoints;
        ws.uniqueDays.add(new Date(task.completedAt!).toLocaleDateString('sk-SK'));
        if (task.startedAt) {
            let exec = task.completedAt! - task.startedAt;
            if (exec > 0) { ws.totalExecutionMs += exec; grandTotalExecutionTime += exec; }
            ws.totalStandardMin += (task.standardTime || 0);
        }
      }

      if (task.workplace && !task.isLogistics) {
        if (!workplacesMap[task.workplace]) workplacesMap[task.workplace] = { load: 0, pal: 0, taskRequests: 0, totalTasks: 0 };
        workplacesMap[task.workplace].load += loadPoints;
      }
      if (hour >= 0 && hour < 24) {
        if (task.isLogistics) hourlyStatsMap[hour].logistics += loadPoints;
        else hourlyStatsMap[hour].production += loadPoints;
      }
    });

    const workerStats = Object.values(workerStatsMap).map((ws: any) => {
      const numDays = Math.max(ws.uniqueDays.size, 1);
      const pureWorkMin = ws.totalExecutionMs / 60000;
      const utilPercent = ((pureWorkMin * 1.15) / (numDays * 450)) * 100;
      const perfRatio = (ws.totalStandardMin > 0 && pureWorkMin > 0) ? (ws.totalStandardMin / pureWorkMin) * 100 : 0;
      const logEfficiency = (ws.totalFullDist + ws.totalEmptyDist) > 0 ? (ws.totalFullDist / (ws.totalFullDist + ws.totalEmptyDist)) * 100 : 50;
      const confidence = ws.missingReported > 0 ? ((ws.missingReported - ws.realErrors) / ws.missingReported) * 100 : 100;
      const index = parseFloat(((confidence/100*3.0) + (Math.min(utilPercent,100)/100*2.5) + (perfRatio > 0 ? Math.min(perfRatio,120)/120*2.0 : 1.5) + (logEfficiency/100*1.0)).toFixed(1));
      return { ...ws, index, utilPercent, perfRatio, logEfficiency };
    }).sort((a, b) => b.index - a.index);

    return { total: performanceTasks.length, done: performanceTasks.filter(t => t.isDone).length, efficiency: performanceTasks.length <= 0 ? 0 : Math.round((performanceTasks.filter(t => t.isDone).length / performanceTasks.length) * 100), totalVolume: Object.values(workerStatsMap).reduce((s, w) => s + w.totalVolume, 0), grandTotalExecutionTime, workerStats, topHighRunners: [], topWorkplaces: Object.entries(workplacesMap).sort(([, a], [, b]) => b.load - a.load).slice(0, 3).map(([wp, d]) => ({ workplace: wp, ...d })), hourlyData: Object.entries(hourlyStatsMap).map(([h, v]) => ({ hour: parseInt(h), label: `${h.padStart(2, '0')}:00`, production: v.production, logistics: v.logistics })), quality: { realErrorsCount, falseAlarmsCount, totalAuditedMissing, topMissingParts: Object.entries(missingPartsMap).sort(([, a], [, b]) => b - a).slice(0, 3).map(([pn, count]) => ({ partNumber: pn, count })) }, sectorStats: [], driving: { totalFullDist: globalFullDist, totalEmptyDist: globalEmptyDist, totalRides: globalRides, logEfficiency: (globalFullDist + globalEmptyDist) > 0 ? (globalFullDist / (globalFullDist + globalEmptyDist)) * 100 : 50 } };
  }, [filteredTasks, systemBreaks, resolveName, shiftFilter, mapSectors, workplaces, systemConfig, VZV_SPEED_MPS, logisticsOperations]);

  const getPeriodLabel = () => {
    switch (filterMode) {
      case 'TODAY': return language === 'sk' ? 'DNES' : 'TODAY';
      case 'YESTERDAY': return language === 'sk' ? 'VČERA' : 'YESTERDAY';
      case 'WEEK': return language === 'sk' ? 'TÝŽDEŇ' : 'WEEK';
      case 'MONTH': return language === 'sk' ? 'MESIAC' : 'MONTH';
      case 'CUSTOM': return `${customStart} - ${customEnd}`;
      default: return '';
    }
  };

  const getIndexColor = (val: number) => val >= 8 ? 'text-emerald-500' : val >= 5 ? 'text-amber-500' : 'text-red-500';

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h1 className="text-2xl sm:text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('analytics_title')}</h1>
      </div>

      {/* FILTER PANEL SECTION */}
      <div className="bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-fade-in flex flex-col">
        <button 
          onClick={() => setIsFilterOpen(!isFilterOpen)}
          className="w-full flex items-center justify-between p-6 bg-amber-600/10 hover:bg-amber-600/20 transition-colors border-b border-amber-600/30"
        >
          <div className="flex items-center gap-4">
            <div className="p-3 bg-amber-500/10 rounded-xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
            </div>
            <div className="text-left">
              <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">FILTER PANEL</h3>
              <p className="text-[9px] text-slate-400 font-bold uppercase mt-0.5">Aktívny filter: {getPeriodLabel()}</p>
            </div>
          </div>
          <div className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
          </div>
        </button>

        {isFilterOpen && (
          <div className="p-8 space-y-10 max-h-[600px] overflow-y-auto custom-scrollbar animate-fade-in bg-slate-900/50">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest block ml-2">Časový rozsah:</h4>
                    <div className="grid grid-cols-2 gap-2">
                        {(['TODAY', 'YESTERDAY', 'WEEK', 'MONTH', 'CUSTOM'] as FilterMode[]).map(m => (
                            <button key={m} onClick={() => setFilterMode(m)} className={`h-12 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filterMode === m ? 'bg-teal-600 text-white shadow-lg' : 'bg-slate-800 text-gray-400 hover:text-white'}`}>{t(`filter_${m.toLowerCase()}` as any)}</button>
                        ))}
                    </div>
                </div>

                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest block ml-2">Zmeny a Zdroj:</h4>
                    <div className="flex flex-col gap-3">
                        <div className="bg-slate-950/80 p-1.5 rounded-2xl flex border border-slate-700 shadow-inner h-14">
                            <button onClick={() => setSourceFilter('ALL')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'ALL' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Všetko' : 'All'}</button>
                            <button onClick={() => setSourceFilter('PRODUCTION')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'PRODUCTION' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{t('mode_production')}</button>
                            <button onClick={() => setSourceFilter('LOGISTICS')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'LOGISTICS' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{t('mode_logistics')}</button>
                        </div>
                        <div className="bg-slate-950/80 p-1.5 rounded-2xl flex border border-slate-700 shadow-inner h-14">
                            <button onClick={() => setShiftFilter('ALL')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'ALL' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Zmeny' : 'Shifts'}</button>
                            <button onClick={() => setShiftFilter('MORNING')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'MORNING' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Ranná' : 'Morning'}</button>
                            <button onClick={() => setShiftFilter('AFTERNOON')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'AFTERNOON' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Poobedná' : 'Afternoon'}</button>
                        </div>
                    </div>
                </div>
            </div>

            {filterMode === 'CUSTOM' && (
                <div className="p-6 bg-slate-950/50 rounded-2xl border-2 border-slate-800 space-y-6 animate-fade-in">
                    <h4 className="text-xs font-black text-amber-500 uppercase tracking-widest text-center">Vlastný rozsah (Aktuálny mesiac)</h4>
                    <div className="grid grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-600 uppercase ml-2">Od:</label>
                            <input type="date" min={firstDayOfMonth} max={lastDayOfMonth} value={customStart} onChange={e => setCustomStart(e.target.value)} className="w-full h-14 bg-slate-900 border-2 border-slate-800 rounded-xl px-4 font-black font-mono text-white focus:border-teal-500 transition-all uppercase" />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-600 uppercase ml-2">Do:</label>
                            <input type="date" min={firstDayOfMonth} max={lastDayOfMonth} value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="w-full h-14 bg-slate-900 border-2 border-slate-800 rounded-xl px-4 font-black font-mono text-white focus:border-teal-500 transition-all uppercase" />
                        </div>
                    </div>
                </div>
            )}
          </div>
        )}
      </div>

      {/* EXPORT PANEL - NAVRÁTENÝ POD FILTRE */}
      <AnalyticsExportPanel 
        canExport={canExport} 
        tasks={filteredTasks} 
        systemBreaks={systemBreaks} 
        resolveName={resolveName} 
        t={t} 
        language={language} 
      />

      {/* KPI SUMMARY TILES */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-5">
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-blue-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_total')}</p>
          <p className="text-3xl font-black text-white mt-2 font-mono leading-none">{stats.total}</p>
          <p className="text-xs font-bold text-blue-400/80 mt-1 uppercase tracking-widest">{stats.totalVolume.toFixed(1)} {language === 'sk' ? 'pal/ks' : 'pal/pcs'}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-emerald-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_worked')}</p>
          <p className="text-3xl font-black text-emerald-400 mt-2 font-mono">{Number((stats.grandTotalExecutionTime / 3600000).toFixed(1))}h</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-purple-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">EFEKTIVITA</p>
          <p className="text-3xl font-black text-purple-400 mt-2 font-mono">{stats.efficiency}%</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-amber-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">REAL JAZDY</p>
          <p className="text-3xl font-black text-amber-400 mt-2 font-mono">{stats.driving.totalRides}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-teal-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">KM (PLNÉ)</p>
          <p className="text-3xl font-black text-teal-400 mt-2 font-mono">{(stats.driving.totalFullDist / 1000).toFixed(1)}</p>
        </div>
      </div>

      <div className="bg-slate-950/40 border border-slate-800 p-6 rounded-3xl shadow-2xl overflow-hidden">
        <div className="flex items-center justify-between mb-8 border-b border-white/5 pb-6">
          <h3 className="text-sm font-black text-white uppercase tracking-[0.25em]">{t('table_title')}</h3>
          <button 
            onClick={() => {}}
            className="bg-green-700 hover:bg-green-600 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-lg active:scale-95 flex items-center gap-2 border border-green-500"
          >
            EXPORT TABUĽKY
          </button>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-separate border-spacing-y-3 min-w-[700px]">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                <th className="pb-4 px-6">{t('th_rank')}</th>
                <th className="pb-4 px-2">{t('th_name')}</th>
                <th className="pb-4 px-2 text-center text-teal-400">INDEX</th>
                <th className="pb-4 px-2 text-right">{t('th_done')}</th>
                <th className="pb-4 px-2 text-right text-sky-400">OBJEM</th>
                <th className="pb-4 px-6 text-right text-emerald-400">ČAS PRÁCE</th>
              </tr>
            </thead>
            <tbody>
              {stats.workerStats.map((ws: any, idx: number) => (
                <tr key={ws.username} className={`group transition-all hover:bg-slate-800/60 ${idx === 0 ? 'bg-slate-800/40 shadow-[0_0_20px_rgba(20,184,166,0.1)]' : 'bg-slate-900/40'}`}>
                  <td className="py-5 px-6 first:rounded-l-2xl text-slate-500 font-mono text-base">{idx + 1}</td>
                  <td 
                    onClick={() => setSelectedWorkerData({ name: ws.name, tasks: filteredTasks.filter(t => t.completedBy === ws.username) })}
                    className="py-5 px-2 font-black text-lg uppercase tracking-tight cursor-pointer hover:text-teal-400 transition-colors"
                  >
                    {ws.name}
                  </td>
                  <td className={`py-5 px-2 text-center font-black font-mono text-xl ${getIndexColor(ws.index)}`}>{ws.index.toFixed(1)}</td>
                  <td className="py-5 px-2 text-right text-teal-500 font-black font-mono text-lg">{ws.count}</td>
                  <td className="py-5 px-2 text-right text-sky-400 font-black font-mono text-lg">{Number(ws.totalVolume.toFixed(1))}</td>
                  <td className="py-5 px-6 last:rounded-r-2xl text-right text-emerald-400 font-black font-mono text-base">{Number((ws.totalExecutionMs / 60000).toFixed(0))}m</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <QualityAuditSection data={stats.quality} t={t} />
      <HighRunnerSection topHighRunners={stats.topHighRunners} topWorkplaces={stats.topWorkplaces} t={t} />
      <HourlyChartSection hourlyData={stats.hourlyData} t={t} />

      <DrivingMetrics 
        totalKm={stats.driving.totalFullDist} 
        emptyKm={stats.driving.totalEmptyDist} 
        rides={stats.driving.totalRides} 
        efficiency={stats.driving.logEfficiency} 
        vzvSpeed={systemConfig.vzvSpeed || 8}
      />

      {selectedWorkerData && (
        <WorkerDetailModal 
          name={selectedWorkerData.name}
          tasks={selectedWorkerData.tasks}
          periodLabel={getPeriodLabel()}
          systemBreaks={systemBreaks}
          onClose={() => setSelectedWorkerData(null)}
          mapSectors={mapSectors}
          workplaces={workplaces}
          systemConfig={systemConfig}
          logisticsOperations={logisticsOperations}
        />
      )}
    </div>
  );
};

export default AnalyticsTab;

