import React, { useMemo, useState, useEffect } from 'react';
import { db } from '../../../firebase';
import { doc, getDoc } from 'firebase/firestore';
import { Task, SystemBreak, MapSector, DBItem, SystemConfig, UserData } from '../../../App';
import { useLanguage } from '../../LanguageContext';
import HighRunnerSection from './HighRunnerSection';
import HourlyChartSection from './HourlyChartSection';
import QualityAuditSection from './QualityAuditSection';
import WorkerDetailModal from './WorkerDetailModal';
import DrivingMetrics from './DrivingMetrics';

declare var XLSX: any;

interface AnalyticsTabProps {
  tasks: Task[];
  onFetchArchivedTasks: () => Promise<Task[]>;
  systemBreaks: SystemBreak[];
  resolveName: (username?: string | null) => string;
  mapSectors: MapSector[];
  workplaces: DBItem[];
  systemConfig: SystemConfig;
  logisticsOperations: DBItem[];
  users: UserData[];
  currentUser: string;
  currentUserRole: string;
  hasPermission: (perm: string) => boolean;
}

type FilterMode = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'CUSTOM';
type ShiftFilter = 'ALL' | 'MORNING' | 'AFTERNOON';
type SourceFilter = 'ALL' | 'PRODUCTION' | 'LOGISTICS';

const AnalyticsTab: React.FC<AnalyticsTabProps> = ({ 
  tasks: _liveTasks, onFetchArchivedTasks, systemBreaks, resolveName, mapSectors, workplaces, systemConfig, logisticsOperations,
  users, currentUser, currentUserRole, hasPermission 
}) => {
  const [filterMode, setFilterMode] = useState<FilterMode>('TODAY');
  const [shiftFilter, setShiftFilter] = useState<ShiftFilter>('ALL');
  const [sourceFilter, setSourceFilter] = useState<SourceFilter>('ALL');
  const [customStart, setCustomStart] = useState('');
  const [customEnd, setCustomEnd] = useState('');
  const [isFilterOpen, setIsFilterOpen] = useState(false);
  const [archivedTasks, setArchivedTasks] = useState<Task[]>([]);
  const [isLoadingArchive, setIsLoadingArchive] = useState(false);
  const [selectedWorkerData, setSelectedWorkerData] = useState<{ name: string; tasks: Task[] } | null>(null);
  const { t, language } = useLanguage();

  const VZV_SPEED_MPS = (systemConfig.vzvSpeed || 8) / 3.6;
  const now = new Date();
  const firstDayOfMonth = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().split('T')[0];
  const lastDayOfMonth = new Date(now.getFullYear(), now.getMonth() + 1, 0).toISOString().split('T')[0];

  const tasks = useMemo(() => archivedTasks, [archivedTasks]);

  useEffect(() => {
    const load = async () => {
      if (isLoadingArchive) return;
      setIsLoadingArchive(true);
      try {
        const results: Task[] = [];
        const startOfMonthTs = new Date(now.getFullYear(), now.getMonth(), 1).getTime();

        const draftSnap = await getDoc(doc(db, 'settings', 'draft'));
        if (draftSnap.exists()) {
            const draftData = draftSnap.data().data || [];
            draftData.forEach((t: any) => {
                if (t.completedAt >= startOfMonthTs) results.push(t);
            });
        }

        const currentYear = now.getFullYear();
        const firstDayOfYear = new Date(currentYear, 0, 1);
        const pastDaysOfYear = (now.getTime() - firstDayOfYear.getTime()) / 86400000;
        const currentWeekNum = Math.ceil((pastDaysOfYear + firstDayOfYear.getDay() + 1) / 7);

        const weeksToCheck = [currentWeekNum, currentWeekNum - 1, currentWeekNum - 2, currentWeekNum - 3, currentWeekNum - 4];
        const sanonPromises = weeksToCheck.filter(w => w > 0).map(w => getDoc(doc(db, 'sanony', `${currentYear}_${w}`)));
        const sanonSnaps = await Promise.all(sanonPromises);

        sanonSnaps.forEach(snap => {
            if (snap.exists()) {
                const tasksInSanon = snap.data().tasks || [];
                tasksInSanon.forEach((t: any) => {
                    if (t.completedAt >= startOfMonthTs) results.push(t);
                });
            }
        });

        setArchivedTasks(results);
      } catch (err) {
        console.error("Archive fetch error:", err);
      } finally {
        setIsLoadingArchive(false);
      }
    };
    load();
  }, [filterMode]);

  const filteredTasks = useMemo(() => {
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    return tasks.filter(task => {
      if (sourceFilter === 'PRODUCTION' && task.isLogistics) return false;
      if (sourceFilter === 'LOGISTICS' && !task.isLogistics) return false;

      const referenceTime = task.completedAt || task.createdAt;
      if (!referenceTime) return false;

      const taskDate = new Date(referenceTime);
      const taskDayStart = new Date(taskDate.getFullYear(), taskDate.getMonth(), taskDate.getDate());

      let passesTimeFilter = false;
      switch (filterMode) {
        case 'TODAY': passesTimeFilter = taskDayStart.getTime() === todayStart.getTime(); break;
        case 'YESTERDAY':
          const yesterdayStart = new Date(todayStart);
          yesterdayStart.setDate(yesterdayStart.getDate() - 1);
          passesTimeFilter = taskDayStart.getTime() === yesterdayStart.getTime();
          break;
        case 'WEEK': passesTimeFilter = referenceTime >= (todayStart.getTime() - (7 * 86400000)); break;
        case 'MONTH': passesTimeFilter = taskDate.getMonth() === now.getMonth() && taskDate.getFullYear() === now.getFullYear(); break;
        case 'CUSTOM':
            if (!customStart || !customEnd) return false;
            const s = new Date(customStart).getTime();
            const e = new Date(customEnd).getTime() + 86399999;
            passesTimeFilter = referenceTime >= s && referenceTime <= e;
            break;
        default: passesTimeFilter = true;
      }

      if (!passesTimeFilter) return false;
      if (shiftFilter === 'ALL') return true;

      const hours = taskDate.getHours();
      if (shiftFilter === 'MORNING') return hours >= 4 && hours < 14;
      if (shiftFilter === 'AFTERNOON') return hours >= 14 && hours < 24;
      return true;
    });
  }, [tasks, filterMode, shiftFilter, sourceFilter, customStart, customEnd]);

  const stats = useMemo(() => {
    const workplacesMap: Record<string, { load: number, pal: number, taskRequests: number, totalTasks: number }> = {};
    const hourlyStatsMap: Record<number, { production: number, logistics: number }> = {};
    const missingPartsMap: Record<string, number> = {};
    const workerStatsMap: Record<string, any> = {};

    for (let i = 0; i < 24; i++) hourlyStatsMap[i] = { production: 0, logistics: 0 };
    let realErrorsCount = 0, totalAuditedMissing = 0, falseAlarmsCount = 0, grandTotalExecutionTime = 0;
    let globalFullDist = 0, globalEmptyDist = 0, globalRides = 0;

    const performanceTasks = filteredTasks.filter(t => t.status !== 'incorrectly_entered' && t.auditResult !== 'NOK');
    performanceTasks.forEach(task => {
      const qtyVal = parseFloat((task.quantity || '0').replace(',', '.'));
      const loadPoints = (task.quantityUnit === 'pallet' && !isNaN(qtyVal)) ? qtyVal : 1;
      const hour = (task.completedAt || task.createdAt) ? new Date(task.completedAt || task.createdAt!).getHours() : -1;

      if (task.isMissing === true) {
        if (task.partNumber) missingPartsMap[task.partNumber] = (missingPartsMap[task.partNumber] || 0) + 1;
        if (task.auditResult) {
          totalAuditedMissing++;
          if (task.auditResult === 'NOK') realErrorsCount++;
          else falseAlarmsCount++;
        }
      }

      if (task.isDone && task.completedBy) {
        const worker = task.completedBy;
        if (!workerStatsMap[worker]) {
            workerStatsMap[worker] = { username: worker, name: resolveName(worker), count: 0, totalVolume: 0, totalExecutionMs: 0, totalStandardMin: 0, totalReactionMs: 0, reactionCount: 0, missingReported: 0, realErrors: 0, uniqueDays: new Set(), totalFullDist: 0, totalEmptyDist: 0, totalRides: 0 };
        }
        const ws = workerStatsMap[worker];
        let validatedTrips = 0, oneWayD = 0;

        if (task.isLogistics) {
            const logOp = logisticsOperations.find(o => o.value === task.workplace);
            if (logOp?.distancePx) {
                oneWayD = logOp.distancePx;
                const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                validatedTrips = Math.min(!isNaN(qtyVal) ? Math.max(1, Math.floor(qtyVal)) : 1, Math.max(1, Math.round(((durationMs/1000)*VZV_SPEED_MPS)/(2*oneWayD))));
            }
        } else if (task.pickedFromSectorId && task.workplace) {
            const sector = mapSectors.find(s => s.id === task.pickedFromSectorId);
            const wp = workplaces.find(w => w.value === task.workplace);
            if (sector && wp) {
                oneWayD = Math.sqrt(Math.pow(wp.coordX!-sector.coordX,2)+Math.pow(wp.coordY!-sector.coordY,2))/10;
                const durationMs = (task.completedAt || 0) - (task.startedAt || task.createdAt || 0);
                validatedTrips = Math.min(!isNaN(qtyVal) ? Math.max(1, Math.floor(qtyVal)) : 1, Math.max(1, Math.round(((durationMs/1000)*VZV_SPEED_MPS)/(2*oneWayD))));
            }
        }

        if (validatedTrips > 0) {
            globalRides += validatedTrips; ws.totalRides += validatedTrips;
            globalFullDist += validatedTrips * oneWayD; ws.totalFullDist += validatedTrips * oneWayD;
            globalEmptyDist += validatedTrips * oneWayD; ws.totalEmptyDist += validatedTrips * oneWayD;
        }
        ws.count += 1; ws.totalVolume += loadPoints;
        ws.uniqueDays.add(new Date(task.completedAt!).toLocaleDateString('sk-SK'));
        if (task.startedAt) {
            let exec = task.completedAt! - task.startedAt;
            if (exec > 0) { ws.totalExecutionMs += exec; grandTotalExecutionTime += exec; }
            ws.totalStandardMin += (task.standardTime || 0);
        }
      }

      if (task.workplace && !task.isLogistics) {
        if (!workplacesMap[task.workplace]) workplacesMap[task.workplace] = { load: 0, pal: 0, taskRequests: 0, totalTasks: 0 };
        workplacesMap[task.workplace].load += loadPoints;
      }
      if (hour >= 0 && hour < 24) {
        if (task.isLogistics) hourlyStatsMap[hour].logistics += loadPoints;
        else hourlyStatsMap[hour].production += loadPoints;
      }
    });

    const workerStats = Object.values(workerStatsMap).map((ws: any) => {
      const numDays = Math.max(ws.uniqueDays.size, 1);
      const pureWorkMin = ws.totalExecutionMs / 60000;
      const utilPercent = ((pureWorkMin * 1.15) / (numDays * 450)) * 100;
      const perfRatio = (ws.totalStandardMin > 0 && pureWorkMin > 0) ? (ws.totalStandardMin / pureWorkMin) * 100 : 0;
      const logEfficiency = (ws.totalFullDist + ws.totalEmptyDist) > 0 ? (ws.totalFullDist / (ws.totalFullDist + ws.totalEmptyDist)) * 100 : 50;
      const confidence = ws.missingReported > 0 ? ((ws.missingReported - ws.realErrors) / ws.missingReported) * 100 : 100;
      const index = parseFloat(((confidence/100*3.0) + (Math.min(utilPercent,100)/100*2.5) + (perfRatio > 0 ? Math.min(perfRatio,120)/120*2.0 : 1.5) + (logEfficiency/100*1.0)).toFixed(1));
      return { ...ws, index, utilPercent, perfRatio, logEfficiency };
    }).sort((a, b) => b.index - a.index);

    return { total: performanceTasks.length, done: performanceTasks.filter(t => t.isDone).length, efficiency: performanceTasks.length <= 0 ? 0 : Math.round((performanceTasks.filter(t => t.isDone).length / performanceTasks.length) * 100), totalVolume: Object.values(workerStatsMap).reduce((s, w) => s + w.totalVolume, 0), grandTotalExecutionTime, workerStats, topHighRunners: [], topWorkplaces: Object.entries(workplacesMap).sort(([, a], [, b]) => b.load - a.load).slice(0, 3).map(([wp, d]) => ({ workplace: wp, ...d })), hourlyData: Object.entries(hourlyStatsMap).map(([h, v]) => ({ hour: parseInt(h), label: `${h.padStart(2, '0')}:00`, production: v.production, logistics: v.logistics })), quality: { realErrorsCount, falseAlarmsCount, totalAuditedMissing, topMissingParts: Object.entries(missingPartsMap).sort(([, a], [, b]) => b - a).slice(0, 3).map(([pn, count]) => ({ partNumber: pn, count })) }, sectorStats: [], driving: { totalFullDist: globalFullDist, totalEmptyDist: globalEmptyDist, totalRides: globalRides, logEfficiency: (globalFullDist + globalEmptyDist) > 0 ? (globalFullDist / (globalFullDist + globalEmptyDist)) * 100 : 50 } };
  }, [filteredTasks, systemBreaks, resolveName, shiftFilter, mapSectors, workplaces, systemConfig, VZV_SPEED_MPS, logisticsOperations]);

  const getPeriodLabel = () => {
    switch (filterMode) {
      case 'TODAY': return language === 'sk' ? 'DNES' : 'TODAY';
      case 'YESTERDAY': return language === 'sk' ? 'VČERA' : 'YESTERDAY';
      case 'WEEK': return language === 'sk' ? 'TÝŽDEŇ' : 'WEEK';
      case 'MONTH': return language === 'sk' ? 'MESIAC' : 'MONTH';
      case 'CUSTOM': return `${customStart} - ${customEnd}`;
      default: return '';
    }
  };

  const getIndexColor = (val: number) => val >= 8 ? 'text-emerald-500' : val >= 5 ? 'text-amber-500' : 'text-red-500';

  const handleFullDataExport = () => {
    if (!filteredTasks.length) {
        alert(language === 'sk' ? 'Žiadne dáta na export.' : 'No data to export.');
        return;
    }

    const formatDate = (ts?: number) => ts ? new Date(ts).toLocaleDateString('sk-SK') : '';
    const formatTime = (ts?: number) => ts ? new Date(ts).toLocaleTimeString('sk-SK') : '';

    const excelData = filteredTasks.map(item => {
        let searchResult = item.searchedBy ? (item.searchExhausted || item.auditResult ? 'Nie' : (item.isMissing === false ? 'Áno' : 'Prebieha')) : '';
        let statusText = item.status === 'incorrectly_entered' ? 'Chybne zadané' : (item.auditResult ? 'Auditované' : (item.isDone ? 'Dokončené' : 'Otvorené'));

        return {
          'ID': item.id,
          'Dátum pridania': formatDate(item.createdAt),
          'Čas pridania': formatTime(item.createdAt),
          'Kto pridal': resolveName(item.createdBy),
          'Diel / Referencia': item.partNumber || '',
          'Pracovisko / Operácia': item.workplace || '',
          'Počet': item.quantity || '',
          'Jednotka': item.quantityUnit || '',
          'Skladník': resolveName(item.completedBy),
          'Dátum dokončenia': formatDate(item.completedAt),
          'Čas dokončenia': formatTime(item.completedAt),
          'Status': statusText,
          'Priorita': item.priority || 'NORMAL',
          'Nahlásil chýbajúce': resolveName(item.missingReportedBy),
          'Dôvod chýbania': item.missingReason || '',
          'Kto hľadal': item.searchedBy || '',
          'Výsledok hľadania': searchResult,
          'Audit (Výsledok)': item.auditResult || '',
          'Audit vykonal': resolveName(item.auditedBy) || item.auditBy || '',
          'Sektor (Odkiaľ)': item.pickedFromSectorId || '-',
          'Poznámka': item.note || ''
        };
    });

    const ws = XLSX.utils.json_to_sheet(excelData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "DATA_EXPORT");
    XLSX.writeFile(wb, `Full_Data_Export_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-20 animate-fade-in text-slate-200">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h1 className="text-2xl sm:text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('analytics_title')}</h1>

        {hasPermission('CAN_EXPORT_FULL_DATA') && (
            <button 
                onClick={handleFullDataExport}
                className="bg-emerald-600 hover:bg-emerald-500 text-white px-8 py-3 rounded-2xl text-xs font-black uppercase tracking-[0.2em] transition-all shadow-xl active:scale-95 border-2 border-emerald-500 flex items-center gap-3"
            >
                <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                {language === 'sk' ? 'EXPORT VŠETKÝCH DÁT' : 'EXPORT FULL DATA'}
            </button>
        )}
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-3xl shadow-2xl overflow-hidden animate-fade-in flex flex-col">
        <button 
          onClick={() => setIsFilterOpen(!isFilterOpen)}
          className="w-full flex items-center justify-between p-6 bg-amber-600/10 hover:bg-amber-600/20 transition-colors border-b border-amber-600/30"
        >
          <div className="flex items-center gap-4">
            <div className="p-3 bg-amber-500/10 rounded-xl">
              <svg xmlns="http://www.w3.org/2000/svg" className="w-6 h-6 text-amber-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
            </div>
            <div className="text-left">
              <h3 className="text-sm font-black text-white uppercase tracking-[0.2em]">FILTER PANEL</h3>
              <p className="text-[9px] text-slate-400 font-bold uppercase mt-0.5">Aktívny filter: {getPeriodLabel()}</p>
            </div>
          </div>
          <div className={`transition-transform duration-300 ${isFilterOpen ? 'rotate-180' : ''}`}>
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M19 9l-7 7-7-7" /></svg>
          </div>
        </button>

        {isFilterOpen && (
          <div className="p-8 space-y-10 max-h-[600px] overflow-y-auto custom-scrollbar animate-fade-in bg-slate-900/50">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest block ml-2">Časový rozsah:</h4>
                    <div className="grid grid-cols-2 gap-2">
                        {(['TODAY', 'YESTERDAY', 'WEEK', 'MONTH', 'CUSTOM'] as FilterMode[]).map(m => (
                            <button key={m} onClick={() => setFilterMode(m)} className={`h-12 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filterMode === m ? 'bg-teal-600 text-white shadow-lg' : 'bg-slate-800 text-gray-400 hover:text-white'}`}>{t(`filter_${m.toLowerCase()}` as any)}</button>
                        ))}
                    </div>
                </div>

                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest block ml-2">Zmeny a Zdroj:</h4>
                    <div className="flex flex-col gap-3">
                        <div className="bg-slate-950/80 p-1.5 rounded-2xl flex border border-slate-700 shadow-inner h-14">
                            <button onClick={() => setSourceFilter('ALL')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'ALL' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Všetko' : 'All'}</button>
                            <button onClick={() => setSourceFilter('PRODUCTION')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'PRODUCTION' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{t('mode_production')}</button>
                            <button onClick={() => setSourceFilter('LOGISTICS')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${sourceFilter === 'LOGISTICS' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{t('mode_logistics')}</button>
                        </div>
                        <div className="bg-slate-950/80 p-1.5 rounded-2xl flex border border-slate-700 shadow-inner h-14">
                            <button onClick={() => setShiftFilter('ALL')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'ALL' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Zmeny' : 'Shifts'}</button>
                            <button onClick={() => setShiftFilter('MORNING')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'MORNING' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Ranná' : 'Morning'}</button>
                            <button onClick={() => setShiftFilter('AFTERNOON')} className={`flex-1 rounded-xl text-[10px] font-black uppercase tracking-widest duration-200 ${shiftFilter === 'AFTERNOON' ? 'bg-teal-600 text-white' : 'text-gray-500'}`}>{language === 'sk' ? 'Poobedná' : 'Afternoon'}</button>
                        </div>
                    </div>
                </div>
            </div>

            {filterMode === 'CUSTOM' && (
                <div className="p-6 bg-slate-950/50 rounded-2xl border-2 border-slate-800 space-y-6 animate-fade-in">
                    <h4 className="text-xs font-black text-amber-500 uppercase tracking-widest text-center">Vlastný rozsah (Aktuálny mesiac)</h4>
                    <div className="grid grid-cols-2 gap-6">
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-600 uppercase ml-2">Od:</label>
                            <input type="date" min={firstDayOfMonth} max={lastDayOfMonth} value={customStart} onChange={e => setCustomStart(e.target.value)} className="w-full h-14 bg-slate-900 border-2 border-slate-800 rounded-xl px-4 font-black font-mono text-white focus:border-teal-500 transition-all uppercase" />
                        </div>
                        <div className="space-y-2">
                            <label className="text-[10px] font-bold text-slate-600 uppercase ml-2">Do:</label>
                            <input type="date" min={firstDayOfMonth} max={lastDayOfMonth} value={customEnd} onChange={e => setCustomEnd(e.target.value)} className="w-full h-14 bg-slate-900 border-2 border-slate-800 rounded-xl px-4 font-black font-mono text-white focus:border-teal-500 transition-all uppercase" />
                        </div>
                    </div>
                </div>
            )}
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-5">
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-blue-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_total')}</p>
          <p className="text-3xl font-black text-white mt-2 font-mono leading-none">{stats.total}</p>
          <p className="text-xs font-bold text-blue-400/80 mt-1 uppercase tracking-widest">{stats.totalVolume.toFixed(1)} {language === 'sk' ? 'pal/ks' : 'pal/pcs'}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-emerald-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">{t('kpi_worked')}</p>
          <p className="text-3xl font-black text-emerald-400 mt-2 font-mono">{Number((stats.grandTotalExecutionTime / 3600000).toFixed(1))}h</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-purple-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">EFEKTIVITA</p>
          <p className="text-3xl font-black text-purple-400 mt-2 font-mono">{stats.efficiency}%</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-amber-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">REAL JAZDY</p>
          <p className="text-3xl font-black text-amber-400 mt-2 font-mono">{stats.driving.totalRides}</p>
        </div>
        <div className="bg-slate-900/60 p-5 rounded-2xl shadow-xl border border-slate-800 border-l-4 border-l-teal-500">
          <p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">KM (PLNÉ)</p>
          <p className="text-3xl font-black text-teal-400 mt-2 font-mono">{(stats.driving.totalFullDist / 1000).toFixed(1)}</p>
        </div>
      </div>

      <div className="bg-slate-950/40 border border-slate-800 p-6 rounded-3xl shadow-2xl overflow-hidden">
        <div className="flex items-center justify-between mb-8 border-b border-white/5 pb-6">
          <h3 className="text-sm font-black text-white uppercase tracking-[0.25em]">{t('table_title')}</h3>
        </div>
        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-separate border-spacing-y-3 min-w-[700px]">
            <thead>
              <tr className="text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                <th className="pb-4 px-6">{t('th_rank')}</th>
                <th className="pb-4 px-2">{t('th_name')}</th>
                <th className="pb-4 px-2 text-center text-teal-400">INDEX</th>
                <th className="pb-4 px-2 text-right">{t('th_done')}</th>
                <th className="pb-4 px-2 text-right text-sky-400">OBJEM</th>
                <th className="pb-4 px-6 text-right text-emerald-400">ČAS PRÁCE</th>
              </tr>
            </thead>
            <tbody>
              {stats.workerStats.map((ws: any, idx: number) => (
                <tr key={ws.username} className={`group transition-all hover:bg-slate-800/60 ${idx === 0 ? 'bg-slate-800/40 shadow-[0_0_20px_rgba(20,184,166,0.1)]' : 'bg-slate-900/40'}`}>
                  <td className="py-5 px-6 first:rounded-l-2xl text-slate-500 font-mono text-base">{idx + 1}</td>
                  <td 
                    onClick={() => setSelectedWorkerData({ name: ws.name, tasks: filteredTasks.filter(t => t.completedBy === ws.username) })}
                    className="py-5 px-2 font-black text-lg uppercase tracking-tight cursor-pointer hover:text-teal-400 transition-colors"
                  >
                    {ws.name}
                  </td>
                  <td className={`py-5 px-2 text-center font-black font-mono text-xl ${getIndexColor(ws.index)}`}>{ws.index.toFixed(1)}</td>
                  <td className="py-5 px-2 text-right text-teal-500 font-black font-mono text-lg">{ws.count}</td>
                  <td className="py-5 px-2 text-right text-sky-400 font-black font-mono text-lg">{Number(ws.totalVolume.toFixed(1))}</td>
                  <td className="py-5 px-6 last:rounded-r-2xl text-right text-emerald-400 font-black font-mono text-base">{Number((ws.totalExecutionMs / 60000).toFixed(0))}m</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      <QualityAuditSection data={stats.quality} t={t} />
      <HighRunnerSection topHighRunners={stats.topHighRunners} topWorkplaces={stats.topWorkplaces} t={t} />
      <HourlyChartSection hourlyData={stats.hourlyData} t={t} />

      <DrivingMetrics 
        totalKm={stats.driving.totalFullDist} 
        emptyKm={stats.driving.totalEmptyDist} 
        rides={stats.driving.totalRides} 
        efficiency={stats.driving.logEfficiency} 
        vzvSpeed={systemConfig.vzvSpeed || 8}
      />

      {selectedWorkerData && (
        <WorkerDetailModal 
          name={selectedWorkerData.name}
          tasks={selectedWorkerData.tasks}
          periodLabel={getPeriodLabel()}
          systemBreaks={systemBreaks}
          onClose={() => setSelectedWorkerData(null)}
          mapSectors={mapSectors}
          workplaces={workplaces}
          systemConfig={systemConfig}
          logisticsOperations={logisticsOperations}
        />
      )}
    </div>
  );
};

export default AnalyticsTab;

import React, { useState } from 'react';
import { createPortal } from 'react-dom';
import { Role, Permission } from '../../App'; 
import { useLanguage } from '../LanguageContext';

interface PermissionsTabProps {
    roles: Role[];
    permissions: Permission[];
    onAddRole: (name: string) => void;
    onDeleteRole: (id: string) => void;
    onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
    onVerifyAdminPassword: (password: string) => boolean;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const LockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
);

const PermissionsTab: React.FC<PermissionsTabProps> = ({ roles, permissions, onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword }) => {
    const { t } = useLanguage();
    const [newRoleName, setNewRoleName] = useState('');

    const [deleteModalRole, setDeleteModalRole] = useState<Role | null>(null);
    const [passwordInput, setPasswordInput] = useState('');
    const [error, setError] = useState('');

    const permGroups = [
      {
          name: 'perm_group_tabs',
          perms: ['perm_tab_entry', 'perm_tab_tasks', 'perm_tab_bom', 'perm_tab_missing', 'perm_tab_inventory', 'perm_tab_logistics_center', 'perm_tab_analytics', 'perm_tab_settings', 'perm_tab_permissions', 'perm_logistics_mode'] 
      },
      {
          name: 'perm_group_actions',
          perms: ['perm_btn_finish', 'perm_btn_edit', 'perm_btn_delete', 'perm_btn_resolve', 'perm_btn_missing', 'perm_btn_copy', 'perm_btn_return', 'perm_btn_note', 'perm_btn_incorrect', 'perm_btn_lock', 'perm_btn_block_new', 'perm_btn_audit', 'perm_view_fullscreen', 'perm_play_sound', 'perm_push_notification', 'perm_view_passwords']
      },
      {
          name: 'perm_group_settings',
          perms: ['perm_view_setup', 'perm_settings_users', 'perm_settings_parts', 'perm_settings_wp', 'perm_settings_bom', 'perm_settings_system', 'perm_settings_maint']
      },
      {
          name: 'perm_group_mgmt',
          perms: ['perm_manage_users', 'perm_delete_users', 'perm_manage_db', 'perm_manage_logistics_ops', 'perm_manage_bom', 'perm_archive', 'perm_manage_breaks', 'perm_manage_roles', 'CAN_EXPORT_FULL_DATA'] 
      }
    ];

    const handleAddRole = (e: React.FormEvent) => {
      e.preventDefault();
      if (newRoleName.trim()) {
          onAddRole(newRoleName.trim());
          setNewRoleName('');
      }
    };

    const hasPermission = (roleId: string, permName: string) => {
        return permissions?.some(p => p.roleId === roleId && p.permissionName === permName) || false;
    };

    const sortedRoles = [...roles].sort((a, b) => {
        if (a.isSystem && !b.isSystem) return -1;
        if (!a.isSystem && b.isSystem) return 1;
        return a.name.localeCompare(b.name);
    });

    const handleDeleteClick = (e: React.MouseEvent, role: Role) => {
        e.preventDefault();
        e.stopPropagation();
        setDeleteModalRole(role);
        setPasswordInput('');
        setError('');
    };

    const handleConfirmDelete = () => {
        if (deleteModalRole) {
            if (onVerifyAdminPassword(passwordInput)) {
                onDeleteRole(deleteModalRole.id);
                setDeleteModalRole(null);
                setPasswordInput('');
                setError('');
            } else {
                setError(t('err_pass_incorrect'));
            }
        }
    };

    const handleCloseModal = () => {
        setDeleteModalRole(null);
        setPasswordInput('');
        setError('');
    };

    return (
        <div className="max-w-6xl mx-auto space-y-10 pb-12 animate-fade-in relative">
            <h1 className="text-center text-3xl sm:text-4xl font-extrabold text-orange-400 mb-8 uppercase tracking-widest">{t('sect_roles')}</h1>

            {permGroups.map(group => (
                 <div key={group.name} className="bg-gray-900 rounded-2xl p-8 shadow-xl border border-gray-700">
                     <h3 className="text-xl font-black text-gray-300 mb-6 border-b border-gray-700 pb-3 uppercase tracking-wider">{t(group.name as any)}</h3>
                     <div className="overflow-x-auto custom-scrollbar"> 
                         <table className="min-w-[700px] w-full text-left text-base border-collapse">
                             <thead>
                                 <tr className="border-b-2 border-gray-700">
                                     <th className="py-4 px-5 text-gray-400 font-bold w-1/3 min-w-[250px] uppercase text-xs tracking-widest">{t('permission_label')}</th> 
                                     {sortedRoles.map(role => (
                                         <th key={role.id} className="py-4 px-5 text-white font-black text-center text-sm tracking-tight">
                                             <div className="flex items-center justify-center gap-3">
                                                 {role.name}
                                                 {role.name !== 'ADMIN' && (
                                                     <button 
                                                         type="button"
                                                         onClick={(e) => handleDeleteClick(e, role)} 
                                                         className="text-red-600 hover:text-red-400 transition-all p-1.5 hover:scale-110 active:scale-90"
                                                         title={t('perm_btn_delete')}
                                                     >
                                                         <TrashIcon className="w-5 h-5" />
                                                     </button>
                                                 )}
                                             </div>
                                         </th>
                                     ))}
                                 </tr>
                             </thead>
                             <tbody className="divide-y divide-gray-800">
                                 {group.perms.map(perm => (
                                     <tr key={perm} className="hover:bg-gray-800/50 transition-colors">
                                         <td className="py-5 px-5 text-gray-300 font-medium">{t(perm as any)}</td>
                                         {sortedRoles.map(role => (
                                             <td key={`${role.id}-${perm}`} className="py-5 px-5 text-center">
                                                 <input 
                                                     type="checkbox" 
                                                     checked={hasPermission(role.id, perm)} 
                                                     onChange={(e) => onUpdatePermission(perm, role.name, e.target.checked)}
                                                     className="w-6 h-6 text-orange-500 bg-gray-700 border-gray-600 rounded-md focus:ring-orange-500 focus:ring-offset-gray-900 focus:ring-2 cursor-pointer" 
                                                 />
                                             </td>
                                         ))}
                                     </tr>
                                 ))}
                             </tbody>
                         </table>
                     </div>
                 </div>
             ))}

            <div className="bg-gray-900 rounded-2xl p-8 shadow-xl border border-gray-700">
                 <h3 className="text-xl font-black text-gray-300 mb-6 uppercase tracking-wider">{t('role_add_new_title')}</h3> 
                 <form onSubmit={handleAddRole} className="flex flex-col sm:flex-row gap-4 max-w-md mt-6">
                     <input value={newRoleName} onChange={e => setNewRoleName(e.target.value)} placeholder={t('role_name_place')} className="flex-1 h-12 bg-gray-700 border border-gray-600 rounded-xl px-5 text-white text-base uppercase font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-orange-500" />
                     <button type="submit" className="h-12 bg-orange-600 hover:bg-orange-700 text-white px-8 rounded-xl font-black uppercase text-xs tracking-widest border-2 border-orange-500 shadow-lg active:scale-95 transition-all">PRIDAŤ</button>
                 </form>
             </div>

             {deleteModalRole && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={handleCloseModal}>
                    <div className="bg-gray-800 border-2 border-red-600 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <div className="w-20 h-20 bg-red-900/30 rounded-full flex items-center justify-center mx-auto mb-6 border border-red-500/50">
                                <LockIcon className="w-10 h-10 text-red-500" />
                            </div>
                            <h3 className="text-2xl font-black text-white mb-3 uppercase tracking-tighter">{t('role_delete_modal_title')}</h3>
                            <p className="text-gray-400 text-base">
                                {t('role_delete_confirm')}
                                <br/>
                                <span className="font-black text-red-400 text-lg mt-1 block">{deleteModalRole.name}</span>
                            </p>
                        </div>

                        <div className="mb-8">
                            <label className="block text-gray-400 text-sm font-black uppercase mb-3 tracking-widest">{t('role_delete_pass_label')}</label>
                            <input 
                                type="password" 
                                value={passwordInput} 
                                onChange={(e) => {
                                    setPasswordInput(e.target.value);
                                    setError('');
                                }}
                                className="w-full h-12 bg-gray-700 border border-gray-600 rounded-xl text-white px-5 focus:outline-none focus:ring-2 focus:ring-red-500 text-base placeholder-gray-500"
                                placeholder="********"
                                autoFocus
                            />
                            {error && <p className="text-red-500 text-sm mt-3 font-bold animate-pulse">{error}</p>}
                        </div>

                        <div className="flex gap-4">
                             <button 
                                onClick={handleCloseModal} 
                                className="flex-1 h-12 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs"
                            >
                                {t('btn_cancel')}
                            </button>
                            <button 
                                onClick={handleConfirmDelete} 
                                disabled={!passwordInput}
                                className={`flex-1 h-12 text-white rounded-xl font-black transition-all shadow-xl flex items-center justify-center gap-3 uppercase text-xs border-2 ${!passwordInput ? 'bg-red-900/50 border-red-900/50 cursor-not-allowed text-gray-400' : 'bg-red-600 hover:bg-red-700 border-red-500'}`}
                            >
                                <TrashIcon className="w-6 h-6" />
                                {t('role_delete_btn')}
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default PermissionsTab;

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import TaskList from './TaskList';
import SettingsTab from '../settings/SettingsTab';
import AnalyticsTab from './Analytics/AnalyticsTab';
import MissingItemsTab from './MissingItemsTab';
import LogisticsCenterTab from './LogisticsCenterTab';
import InventoryTab from './InventoryTab';
import PermissionsTab from './PermissionsTab';
import BOMScreen from './BOMScreen';
import ProductionEntry from './ProductionEntry';
import PartCatalogTab from './PartCatalogTab';
import AppHeader from '../AppHeader';
import TabNavigator from '../TabNavigator';
import { UserData, DBItem, PartRequest, BreakSchedule, SystemBreak, BOMComponent, BOMRequest, Role, Permission, Task, Notification as AppNotification, PriorityLevel, SystemConfig, MapSector } from '../../App';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface PartSearchScreenProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  tasks: Task[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean, note?: string) => void; 
  onUpdateTask: (id: string, updates: Partial<Task>) => void;
  onToggleTask: (id: string) => void;
  onMarkAsIncorrect: (id: string) => void;
  onEditTask: (id: string, newText: string, newPriority?: PriorityLevel) => void;
  onDeleteTask: (id: string) => void;
  onToggleMissing: (id: string, reason?: string) => void; 
  onSetInProgress: (id: string) => void;
  onToggleBlock: (id: string) => void; 
  onToggleManualBlock: (id: string) => void;
  onExhaustSearch: (id: string) => void;
  onAddNote: (id: string, note: string) => void;
  onDeleteMissingItem: (id: string) => void;
  onDeleteMissingReason: (id: string) => void;
  onReleaseTask: (id: string) => void;
  onArchiveTasks: () => Promise<{ success: boolean; count?: number; error?: string; message?: string }>;
  onDailyClosing: () => Promise<{ success: boolean; count: number }>;
  onWeeklyClosing: () => Promise<{ success: boolean; count: number; sanon?: string }>;
  onFetchArchivedTasks: () => Promise<Task[]>;
  onStartAudit: (id: string) => void;
  onFinishAudit: (id: string, result: 'found' | 'missing', note: string) => void;
  onVerifyAdminPassword: (password: string) => boolean;
  onGetDocCount: () => Promise<number>;
  onPurgeOldTasks: () => Promise<number>;
  onExportTasksJSON: () => Promise<void>;
  users: UserData[];
  onAddUser: (user: UserData) => void;
  onUpdatePassword: (username: string, newPass: string) => void;
  onUpdateNickname: (username: string, newNick: string) => void;
  onUpdateUserRole: (username: string, newRole: any) => void;
  onDeleteUser: (username: string) => void;
  parts: DBItem[];
  workplaces: DBItem[];
  missingReasons: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
  onAddWorkplace: (val: string, time?: number) => void;
  onUpdateWorkplace: (id: string, updates: Partial<DBItem>) => void;
  onBatchAddWorkplaces: (vals: string[]) => void;
  onDeleteWorkplace: (id: string) => void;
  onDeleteAllAllWorkplaces?: () => void; 
  onDeleteAllWorkplaces: () => void;
  onAddMissingReason: (val: string) => void;
  logisticsOperations: DBItem[];
  onAddLogisticsOperation: (val: string, time?: number, dist?: number) => void; 
  onUpdateLogisticsOperation: (id: string, updates: Partial<DBItem>) => void;
  onDeleteLogisticsOperation: (id: string) => void;
  mapSectors: MapSector[];
  onAddMapSector: (name: string, x: number, y: number) => void;
  onDeleteMapSector: (id: string) => void;
  onUpdateMapSector: (id: string, updates: Partial<MapSector>) => void;
  partRequests: PartRequest[];
  onRequestPart: (part: string) => Promise<boolean>;
  onApprovePartRequest: (req: PartRequest) => void;
  onRejectPartRequest: (id: string) => void;
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  onAddBreakSchedule: (start: string, end: string) => void;
  onDeleteBreakSchedule: (id: string) => void;
  bomMap: Record<string, BOMComponent[]>;
  bomRequests: BOMRequest[];
  onAddBOMItem: (parent: string, child: string, qty: number) => void;
  onBatchAddBOMItems: (vals: string[]) => void;
  onDeleteBOMItem: (parent: string, child: string) => void;
  onDeleteAllBOMItems: () => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  onApproveBOMRequest: (req: BOMRequest) => void;
  onRejectBOMRequest: (id: string) => void;
  roles: Role[];
  permissions: Permission[];
  onAddRole: (name: string) => void;
  onDeleteRole: (id: string) => void;
  onUpdatePermission: (permissionId: string, roleName: string, hasPermission: boolean) => void;
  notifications: AppNotification[];
  onClearNotification: (id: string) => void;
  installPrompt: any;
  onInstallApp: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  dbLoadWarning: boolean;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
}

const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const ClockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleBlock, onToggleManualBlock, onExhaustSearch, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks, onDailyClosing, onWeeklyClosing,
    breakSchedules,
    bomMap, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning, onGetDocCount, onPurgeOldTasks, onExportTasksJSON,
    mapSectors
  } = props;

  const { t, language, setLanguage } = useLanguage();

  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');
  const [selectedPart, setSelectedPart] = useState<DBItem | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [logisticsPlate, setLogisticsPlate] = useState('');
  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory' | 'catalog'>('entry');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const [auditStartTask, setAuditStartTask] = useState<Task | null>(null);
  const [auditFinishTask, setAuditFinishTask] = useState<Task | null>(null);
  const [auditNote, setAuditNote] = useState('');

  const [searchConfirmTask, setSearchConfirmTask] = useState<Task | null>(null);

  const unitLock = useMemo(() => {
    if (entryMode === 'logistics' || !selectedPart?.description) return null;
    const desc = selectedPart.description;
    if (desc.includes('S0001S')) return 'pcs';
    if (desc.includes('S0002S')) return 'boxes';
    if (desc.includes('S0003S')) return 'pallet';
    return null;
  }, [selectedPart, entryMode]);

  useEffect(() => {
    if (unitLock) {
      setQuantityUnit(unitLock);
    }
  }, [unitLock]);

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const resolveName = useCallback((username?: string | null) => {
      if (!username) return '-';
      const u = users.find(x => x.username === username);
      return (u?.nickname || username).toUpperCase();
  }, [users]);

  const unfinishedTasksCount = tasks.filter(t => !t.isDone).length;
  const pendingRequestsCount = props.partRequests.length + props.bomRequests.length;

  const partNumbersList = useMemo(() => parts.map(p => p.value), [parts]);

  const [hasInitialData, setHasInitialData] = useState(false);
  const [syncTimeout, setSyncTimeout] = useState(false);

  useEffect(() => {
    if (parts.length > 0) {
        setHasInitialData(true);
    }
  }, [parts.length]);

  useEffect(() => {
      const timer = setTimeout(() => {
          if (!hasInitialData) setSyncTimeout(true);
      }, 5000);
      return () => clearTimeout(timer);
  }, [hasInitialData]);

  const isDataLoading = !hasInitialData && !syncTimeout;

  const logisticsOperationsList = useMemo(() => {
      if (props.logisticsOperations && props.logisticsOperations.length > 0) {
          return props.logisticsOperations;
      }
      return [
          { id: 'op_unloading', value: t('op_unloading') },
          { id: 'op_loading', value: t('op_loading') },
          { id: 'op_putaway', value: t('op_putaway') },
          { id: 'op_move', value: t('op_move') }
      ];
  }, [props.logisticsOperations, t]);

  useEffect(() => {
      if (entryMode === 'logistics') {
          setQuantityUnit('pallet');
      } else {
          setQuantityUnit('pcs');
      }
  }, [entryMode]);

  const handleSendToTasks = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) {
            alert(t('fill_all_fields')); 
            return;
        }
        onAddTask(selectedPart.value, selectedWorkplace, quantity, quantityUnit, priority, false);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) {
            alert(t('fill_all_fields'));
            return;
        }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true, logisticsPlate);
    }

    setSelectedPart(null);
    setSelectedWorkplace(null);
    setLogisticsRef('');
    setLogisticsOp('');
    setLogisticsPlate('');
    setQuantity('');
    if (entryMode === 'logistics') { setQuantityUnit('pallet'); } else { setQuantityUnit('pcs'); }
    setPriority('NORMAL'); 
    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const handleAuditClick = (task: Task) => {
      if (task.isAuditInProgress) { setAuditFinishTask(task); setAuditNote(''); } else { setAuditStartTask(task); }
  };

  const handleConfirmStartAudit = () => { if (auditStartTask) { props.onStartAudit(auditStartTask.id); setAuditStartTask(null); } };
  const handleConfirmFinishAudit = (result: 'found' | 'missing', note: string) => { if (auditFinishTask && note.trim()) { props.onFinishAudit(auditFinishTask.id, result, note.trim()); setAuditFinishTask(null); } else { alert(t('fill_all_fields')); } };

  const handleSearchIconClick = (id: string) => {
      const task = tasks.find(t => t.id === id);
      if (!task) return;
      const u = users.find(x => x.username === currentUser);
      const nickname = u?.nickname || currentUser;
      if (task.isBlocked) {
          onUpdateTask(id, { searchedBy: nickname });
          setSearchConfirmTask(task);
      } else {
          onToggleBlock(id);
      }
  };

  const handleConfirmFoundItem = (found: boolean) => {
      if (!searchConfirmTask) return;
      if (found) {
          onToggleMissing(searchConfirmTask.id);
      } else {
          onExhaustSearch(searchConfirmTask.id);
      }
      setSearchConfirmTask(null);
  };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      {notifications.length > 0 && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4">
              <div className="bg-gray-800 rounded-2xl max-w-2xl w-full p-8 shadow-2xl border border-gray-700 animate-fade-in">
                  <div className="flex items-center justify-between mb-6 border-b border-gray-700 pb-4">
                      <h3 className="text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('alert_missing_title')}</h3>
                      <span className="bg-teal-500/20 text-teal-400 px-3 py-1 rounded-full text-xs font-bold">{notifications.length}</span>
                  </div>
                  <div className="space-y-4 max-h-[60vh] overflow-y-auto custom-scrollbar pr-2">
                      {notifications.map(notif => {
                          const isAudit = notif.reason.toUpperCase().includes('AUDIT');
                          const itemBgClass = isAudit ? "bg-amber-900/20 border-amber-800/40" : "bg-red-900/20 border-red-800/40";
                          const iconColorClass = isAudit ? "text-amber-400" : "text-red-400";
                          return (
                              <div key={notif.id} className={`${itemBgClass} border p-5 rounded-xl flex items-center justify-between gap-6 transition-all hover:bg-opacity-30`}>
                                  <div className="flex-grow min-w-0">
                                      <div className="flex items-center gap-3 mb-1">
                                          <div className={`w-2 h-2 rounded-full ${isAudit ? 'bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.6)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'}`}></div>
                                          <p className="font-mono font-black text-2xl text-white uppercase truncate">{notif.partNumber}</p>
                                      </div>
                                      <p className="text-lg text-gray-200 font-medium leading-tight mb-2">{notif.reason}</p>
                                      <div className="flex items-center gap-4 text-sm text-gray-500 font-bold uppercase tracking-wide">
                                          <span className={iconColorClass + " truncate max-w-[120px]"}>{resolveName(notif.reportedBy)}</span>
                                          <span className="opacity-50">•</span>
                                          <span>{new Date(notif.timestamp).toLocaleString('sk-SK', {hour:'2-digit', minute:'2-digit', day:'2-digit', month:'2-digit'})}</span>
                                      </div>
                                  </div>
                                  <button onClick={() => props.onClearNotification(notif.id)} className="flex-shrink-0 bg-gray-900/50 text-gray-400 hover:text-white p-3 rounded-xl hover:bg-gray-700 transition-all active:scale-90">
                                      <CheckCircleIcon className="w-8 h-8" />
                                  </button>
                              </div>
                          );
                      })}
                  </div>
                  <div className="mt-8 flex gap-4">
                      <button onClick={() => notifications.forEach(n => props.onClearNotification(n.id))} className="flex-1 py-4 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-black text-lg shadow-xl transition-all active:scale-[0.98] uppercase tracking-widest">{t('alert_btn_ok')}</button>
                  </div>
              </div>
          </div>
      )}

      {props.isBreakActive && (
        <div className="w-full px-2 sm:px-4 pt-2 z-50 bg-gray-900">
            <div className="w-full bg-red-600 text-white py-5 rounded-xl shadow-[0_0_20px_rgba(220,38,38,0.6)] flex items-center justify-center gap-4 animate-pulse border-2 border-red-400">
                <ClockIcon className="w-10 h-10 flex-shrink-0" />
                <span className="font-black text-2xl sm:text-3xl uppercase tracking-[0.2em] length-none text-center">PREBIEHA PRESTÁVKA</span>
            </div>
        </div>
      )}

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} users={users} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={isFullscreen} onToggleFullscreen={handleToggleFullscreen} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} resolveName={resolveName} />

      {isDataLoading && activeTab === 'entry' ? (
          <div className="flex-grow flex items-center justify-center bg-gray-900">
              <div className="text-center space-y-6">
                  <div className="inline-block w-14 h-14 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="text-teal-400 font-black animate-pulse uppercase tracking-[0.2em] text-base">Synchronizujem databázu dielov...</p>
                  <p className="text-gray-600 text-sm">Pokúšam sa nadviazať spojenie so serverom.</p>
              </div>
          </div>
      ) : (
          <>
            <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: unfinishedTasksCount, pendingRequests: pendingRequestsCount }} />

            <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
                <div className="max-w-7xl mx-auto w-full h-full">
                {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                    <ProductionEntry 
                        mode={entryMode} 
                        setMode={setEntryMode} 
                        selectedPart={selectedPart} 
                        setSelectedPart={setSelectedPart} 
                        selectedWorkplace={selectedWorkplace} 
                        setSelectedWorkplace={setSelectedWorkplace} 
                        logisticsRef={logisticsRef} 
                        setLogisticsRef={setLogisticsRef} 
                        logisticsPlate={logisticsPlate} 
                        setLogisticsPlate={setLogisticsPlate} 
                        logisticsOp={logisticsOp} 
                        setLogisticsOp={setLogisticsOp} 
                        quantity={quantity} 
                        setQuantity={setQuantity} 
                        quantityUnit={quantityUnit} 
                        setQuantityUnit={setQuantityUnit} 
                        priority={priority} 
                        setPriority={setPriority} 
                        parts={parts} 
                        workplaces={workplaces} 
                        logisticsOperationsList={logisticsOperationsList} 
                        t={t} 
                        language={language} 
                        hasPermission={hasPermission} 
                        handleAdd={handleSendToTasks} 
                        onRequestPart={props.onRequestPart}
                        isUnitLocked={!!unitLock} 
                    />
                )}
                {activeTab === 'catalog' && hasPermission('perm_tab_catalog') && (
                    <PartCatalogTab 
                        parts={props.parts} 
                        onSelectPart={(p: any) => {
                          setSelectedPart(p);
                          setActiveTab('entry');
                        }} 
                    />
                )}
                {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                    <div className="animate-fade-in pb-20">
                    <div className="mb-6 flex justify-center">
                        <input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base" placeholder={t('task_search_placeholder')} />
                    </div>
                    <TaskList 
                        currentUser={currentUserRole} 
                        currentUserName={currentUser} 
                        tasks={tasks.filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} 
                        onToggleTask={onToggleTask} 
                        onEditTask={onEditTask} 
                        onDeleteTask={onDeleteTask} 
                        onToggleMissing={onToggleMissing} 
                        onSetInProgress={onSetInProgress} 
                        onToggleBlock={handleSearchIconClick} 
                        onToggleManualBlock={onToggleManualBlock} 
                        onExhaustSearch={onExhaustSearch} 
                        onMarkAsIncorrect={onMarkAsIncorrect} 
                        onAddNote={onAddNote} 
                        onReleaseTask={onReleaseTask} 
                        onAuditPart={handleAuditClick} 
                        resolveName={resolveName} 
                        missingReasons={missingReasons} 
                        hasPermission={hasPermission} 
                    />
                    </div>
                )}
                {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && (
                    <AnalyticsTab 
                        tasks={tasks} 
                        onFetchArchivedTasks={props.onFetchArchivedTasks} 
                        systemBreaks={props.systemBreaks} 
                        resolveName={resolveName} 
